/**
 * CRUD wrapper
 */

(function () {

  'use strict';

  function generic($this, verb, arg1, arg2) {
    logger.d("[CRUD/" + verb + "] triggered");

    // check if there is a callback function and/or options object
    var callback;
    var options = {};


    if (typeof arg1 === 'function') {
      callback = arg1;

      if (typeof arg2 === 'object' && !Array.isArray(arg2)) {
        options = arg2;
      }

    } else if (typeof arg1 === 'object' && !Array.isArray(arg1)) {
      options = arg1;
    } else if (typeof arg1 !== 'undefined') {
      throw TypeError('Invalid arguments on ubi.' + verb.toLowerCase() + '()');
    }

    // TODO - Check if $this is string in order to skip $this DOM object and continue with the rest call
    var $this = $($this);

    if ($this.hasClass('loading')) {
      logger.i("CRUD is in use. Please wait.");
      return;
    }

    var formID = $this.attr('form'); //TODO - Check form attribute in old browsers (check in IE11 - passed)
    var hasForm = (formID !== undefined && formID != "") ? true : false;

    // Make some decisions before call innerCrud()
    // TODO - data attributes for alertifyJS (type, title, message)
    if (verb == "DELETE") {

        if($this.attr('data-custom') != null) /*&& $this.attr('data-payment') === "true" )*/ {

            var now = new Date();
            var nowplus48hours = -1;

            if($this.attr('data-paymenthours') !== undefined) {
                nowplus48hours = new Date(now.getTime() + ($this.attr('data-paymenthours') * 60 * 60 * 1000));
            }

            var targetDate = new Date($this.attr('data-custom'));

            if ((nowplus48hours !== -1) && (nowplus48hours >= targetDate || $this.attr('data-refund') !== "true" || $this.attr('data-refund') === "false") || $this.attr('data-paymenthours') === undefined) {
                alertify.confirm(getKeyTranslation("frontend.message.delete.title"),
                    getKeyTranslation("frontend.message.delete.message") + "<br>" + "<br>" +
                    getKeyTranslation("frontend.paymentdelete"), // because the cancellation is made less than 48 hours prior to the appointment or your country does not permit refund.",
                    innerCrud,
                    function () {
                        logger.i("Deletion cancelled");
                    }
                ).set({
                    labels: {ok: getKeyTranslation("frontend.message.delete.ok"), cancel: getKeyTranslation("frontend.message.delete.cancel")},
                    reverseButtons: true,
                    transition: 'fade'
                });
            } else {
                alertify.confirm(getKeyTranslation("frontend.message.delete.title"),
                    getKeyTranslation("frontend.message.delete.message") + "<br>" + "<br>" +
                    getKeyTranslation("frontend.message.delete.refundMessage1") + $this.attr('data-paymenthours') + getKeyTranslation("frontend.message.delete.refundMessage2"),
                   // "If you have paid for this appointment, the money will be refunded because the cancellation is made more than 48 hours prior to the appointment.",
                    innerCrud,
                    function () {
                        logger.i("Deletion cancelled");
                    }
                ).set({
                    labels: {ok: getKeyTranslation("frontend.message.delete.ok"), cancel: getKeyTranslation("frontend.message.delete.cancel")},
                    reverseButtons: true,
                    transition: 'fade'
                });
            }
        }
        else {
            alertify.confirm(getKeyTranslation("frontend.message.delete.title"), getKeyTranslation("frontend.message.delete.message"),
                innerCrud,
                function () {
                    logger.i("Deletion cancelled");
                }
            ).set({
                labels: {ok: getKeyTranslation("frontend.message.delete.ok"), cancel: getKeyTranslation("frontend.message.delete.cancel")},
                reverseButtons: true,
                transition: 'fade'
            });
        }
    } else if (verb == "EDIT") {

        var now = new Date();
        //var nowplus48hours = new Date(now.getTime() + (48 * 60 * 60 * 1000));
        var nowplus48hours = -1;

        if($this.attr('data-paymenthours') !== undefined) {
            nowplus48hours = new Date(now.getTime() + ($this.attr('data-paymenthours') * 60 * 60 * 1000));
        }


        var targetDate = new Date($this.attr('data-timestamp'));

        console.log(nowplus48hours);
        console.log(targetDate);
        console.log($this.attr('data-timestamp'));


        if( (nowplus48hours !== -1 && $this.attr('data-timestamp') != null && $this.attr('data-payment') === "true" &&  nowplus48hours >= targetDate)
            || (nowplus48hours === -1 && $this.attr('data-payment') === "true")) {
            //because the cancellation is made less than 48 hours prior to the appointment
            alertify.confirm("Edit",
                getKeyTranslation("frontend.editagain")+ "<br>" + "<br>" +
                getKeyTranslation("frontend.editpayagain"),
                function () {
                    window.location.href =  $this.attr('data-submit')
                },
                function () {
                    logger.i("Deletion cancelled");
                }
            ).set({
                labels: {ok: "Edit", cancel: getKeyTranslation("frontend.message.delete.cancel")},
                reverseButtons: false,
                transition: 'fade'
            });
        } else {
            window.location.href =  $this.attr('data-submit');
        }
    }
    else if (hasForm && !options.skipValidation) {
      var validatorResult = ubi.validator.validate(formID, innerCrud);
      if (!validatorResult) {
        logger.e("Please check the form fields again");
        ubi.scrollToSpecificElement('.parsley-error', 70, 500, true);

        return false;
      }
    } else {
      innerCrud();
    }

    function innerCrud() {
      // Define API
      var API_URL;
      if ($this.attr('data-submit') !== undefined && $this.attr('data-submit')
          != "" && $this.attr('data-submit') != null) {
        API_URL = ubi.API_URL_PREFIX + $this.attr('data-submit');
      } else {
        throw new TypeError("'data-submit' attribute couldn't be found.");
      }

      var ajaxOptions = {
        url: API_URL,
        type: verb
      };

      if (hasForm) {
        // Define form
        var $form = $('form#' + formID);
        if ($form.length < 1) {
          throw new TypeError("No form found with id='" + formID + "'");
        }

        var fields = $form.serializeJSON(serializeJSON_OPTIONS);
        var field;
        for (field in fields) {
          if (typeof fields[field] === 'string') {
            fields[field] = fields[field].trim();
          }
        }

        ajaxOptions.data = JSON.stringify(fields);
        ajaxOptions.contentType = "application/json; charset=utf-8";
      }

      // Start CRUDer
      $this.addClass('loading');
      
      var loadAllPage = "false";
      if ($this.attr('loadAllPage') !== undefined && $this.attr('loadAllPage')
          != "" && $this.attr('loadAllPage') != null) {
        loadAllPage = $this.attr('loadAllPage')
      }      
      if (loadAllPage === "true"){
        $('html').hasClass('modal') ? ubi.loader.modal.start() : ubi.loader.nonBlocking.start();
      }
      

      var customRedirect;
      customRedirect = $this.attr('data-redirect') !== 'undefined'
        && $this.attr('data-redirect') !== "" ? $this.attr('data-redirect') : undefined;


      $.ajax(ajaxOptions).done(function (data, textStatus, jqXHR) {

          if(data.message !== undefined && data.message.toUpperCase() === "REDIRECTPAYMENT") {
              window.location.href = data.returnobject;
              return;
          }

        //Check if the new record is created
        if (textStatus.toUpperCase() == "SUCCESS" && (data == "" || data === undefined || data.code.toUpperCase() === "SUCCESS")) {
          setTimeout(function () {

            var redirectURL;
            var pathname = window.location.pathname + window.location.search;

            if (typeof customRedirect !== 'undefined' && typeof customRedirect === 'string') {
              redirectURL = customRedirect;
            } else if ("returnobject" in data && typeof data.returnobject === 'object'
                && data.returnobject != null && "redirectURL" in data.returnobject) {
              redirectURL = data.returnobject.redirectURL;
            } else {
              // Initialize redirect URL. By default it reloads current page
              redirectURL = pathname;
            }

            // Inform user
            logger.i("Successful API communication at \"" + API_URL
                + "\" using method " + verb);

            data != "" && "message" in data && data.message != null
                ? alertify.success(data.message)
                : null;

            // Remove loader
            $this.removeClass('loading');
            if (loadAllPage === "true"){
                $('html').hasClass('modal') ? ubi.loader.modal.stop() : ubi.loader.nonBlocking.stop();
            }

            // Redirection
            if (window.location.search.indexOf('redirect=') !== -1) {
              window.history.back();
            } else {
              redirectURL != "stay" ? page(redirectURL) : null;
            }

            /*if (typeof callback === 'function') {

              callback(data, textStatus, jqXHR);

            }*/

          }, ubi.loader.blocking.loadingTime);
        } else {
          "message" in data ? alertify.error(data.message) : alertify.error(
              getKeyTranslation("frontend.message.error.1")); //"Something went wrong. Please contact the system administrator."
          $this.removeClass('loading');
          if (loadAllPage === "true"){
            $('html').hasClass('modal') ? ubi.loader.modal.stop() : ubi.loader.nonBlocking.stop();
          }
        }

        if (typeof callback === 'function') {

          callback(data, textStatus, jqXHR);

        }
      }).fail(function (jqXHR, textStatus, errorThrown) {
        let message = getKeyTranslation("frontend.message.error.2");//"Something went wrong. Try again later."        
   
        if (jqXHR.status === 401 && API_URL === '/api/v1/auth/login'){
            message = getKeyTranslation("frontend.message.error.3");//Bad credentials
        }else if (jqXHR.status === 468 && API_URL === '/api/v1/auth/login'){
            message = getKeyTranslation("frontend.message.error.user.disabled");
        }else if (jqXHR.status === 469 && API_URL === '/api/v1/auth/login'){
            message = getKeyTranslation("frontend.message.error.user.blocked");
        }else if (jqXHR.status === 470 && API_URL === '/api/v1/auth/login'){
            message = getKeyTranslation("frontend.message.error.user.not.verified");
        }
        else if (jqXHR.status === 451){
            message = "Unavailable For Legal Reasons";
        }
        
        "responseJSON" in jqXHR && "message" in jqXHR.responseJSON
            ? alertify.error(jqXHR.responseJSON.message) : alertify.error(message); 
        $this.removeClass('loading');
        if (loadAllPage === "true"){
            $('html').hasClass('modal') ? ubi.loader.modal.stop() : ubi.loader.nonBlocking.stop();
        }
      });
    }//End of inner function

  };
  
  function getLanguage() {
        var language;
        language = getCookie('org.springframework.web.servlet.i18n.CookieLocaleResolver.LOCALE');
        return language;
   }//EoM
   
   function getCookie(cn) {
        var name = cn + "=";
        var allCookie = decodeURIComponent(document.cookie).split(';');
        var cval = [];
        for (var i = 0; i < allCookie.length; i++) {
            if (allCookie[i].trim().indexOf(name) == 0) {
                cval = allCookie[i].trim().split("=");
            }
        }
        return (cval.length > 0) ? cval[1] : "";
    }//EoM
  
  function getTranslation(key, array) {
        var ret = key;
        var localforkey = 'en';
        var lang = getLanguage();
        if (lang === 'ru-RU' || lang === 'ru')
            localforkey = 'ru';
        if (lang === 'am-AM' || lang === 'am')
            localforkey = 'am';
        if (lang === 'cn-CN' || lang === 'cn')
            localforkey = 'cn';
        if (lang.startsWith("ar-") || lang === 'ar')
            localforkey = 'ar';
        if (lang === 'ku')
            localforkey = 'ku';
        if (lang.startsWith("sr-") || lang === 'sr')
            localforkey = 'sr';
        if (lang.startsWith("sq-") || lang === 'sq')
            localforkey = 'sq';
        if (lang.startsWith("in-") || lang === 'in')
            localforkey = 'in';

        for (var i = 0; i < array.length; i++) {
            //console.log(array[i].key, array[i].locale, array[i].content);
            if (array[i].key == key && array[i].locale == localforkey)
                ret = array[i].content;
        }
        return ret;
    }//EoM

    function getKeyTranslation(key) {
        return getTranslation(key, transarray);
    }
    
    function getTranslationExt(key) {
        return getTranslation(key, transarray);
    }
    
    var transarray;

    $.get({
        url: "/api/v1/translations",
        //url: "/api/v1/translations/messages",
        contentType: "application/json; charset=utf-8"
    }).done(function (data, status, xhr) {
        if ("SUCCESS" === data.code) {
            //console.log(data.returnobject);
            transarray = data.returnobject;
        }
    });
            

  /*
   * CRUD methods
   *
   * @param {object} this - The object of the clicked element
   * @param {function} callback - A callback function
   * @param {object} options - Options object to parameterize requests
   *  {
   *      {boolean} skipValidation: true | false
   *  }
   */
  var crud = {
    get: function ($this, callback) {
      logger.i("[CRUD/GET] is under construction");
    },

    post: function ($this) {
      generic($this, 'POST', arguments[1], arguments[2]);
    },

    put: function ($this) {
      generic($this, 'PUT', arguments[1], arguments[2]);
    },

    delete: function ($this) {
      generic($this, 'DELETE', arguments[1], arguments[2]);
    },

    edit: function ($this) {
      generic($this, 'EDIT', arguments[1], arguments[2]);
    }
  };

  ubi.crud = crud;
  ubi.getKeyTranslation = getKeyTranslation; 
  ubi.getTranslationExt = getTranslationExt;  

})();

/**
 * A javascript wrapper for Audio
 */

(function () {

    ubi.audio = {};


    /**
     * Creates a new object with @objectName and set their an Audio instance based on the @filename
     *
     * @param objectName
     * @param filename
     */
    ubi.audio.create = function (objectName, filepath) {
        try {
            ubi.audio[objectName] = new Audio(filepath)
        } catch(e) {
            throw new Error(e)
        }
    };

    try {
        if ('Audio' in window) {
            Audio.prototype.stop = function() {
                this.pause();
                this.currentTime = 0;
                return this;
            };
        } else {
            throw new Error("HTML5 Audio is not supported for this browser")
        }
    } catch(e) {
        logger.e(e)
    }

})();
