/**
 * Auth
 */

(function() {

    "use strict";

    ubi.loginHandler = function($this) {
        ubi.crud.post($this, function(data, textStatus, jqXHR) {
            if (textStatus.toUpperCase() === 'SUCCESS') {                
                ubi.setLogin(true);
                if ($("#destination").val() !== undefined && $("#destination").val()
                    != "" && $("#destination").val() != null) {                    
                    if ($("#destination").val() === "appointments" || $("#destination").val() === "visa-request") {
                        window.location.href = "/"+$("#destination").val()+"/add";
                    }else {
                        window.location.href = "/"+$("#destination").val();
                    }
                }else{
                    ubi.goHome();
                }
            }
        });
        
    };

    ubi.sendOtpHandler = function($this){
                ubi.crud.post($this, function(data, textStatus, jqXHR) {
                    if (textStatus.toUpperCase() === 'SUCCESS') {
                    if(data.code.toUpperCase() === "INVALID" || data.code.toUpperCase() === "EXCEPTION"){
                            alertify.error(data.message, {mode: "notification-error"});
                    }else{
                            $("#btn-register").show();
                            $("#recaptcha").show();
                            $("#onetimepassword-wrap").show();
                            $("#onetimepassword-otp").hide();
                            $("#btn-onetimepassword").hide();
//                            $("#phonenumber").prop("disabled",true);
                            setTimeout(function (){$("#btn-onetimepassword").show()},10000 * 18); //10 seconds(milliseconds) * x to minutes
                            setTimeout(function (){$("#btn-onetimepassword").text("RESEND OTP CODE")},10000  * 18 );
//                            setTimeout(function (){$("#btn-onetimepassword").text(ubi.getKeyTranslation('otp.request.resend'))},10000  * 18 );

                            setTimeout(function (){$("#btn-register").hide()},10000 * 18); //10 seconds(milliseconds) * x to minutes
                            setTimeout(function (){$("#recaptcha").hide()},10000 * 18); //10 seconds(milliseconds) * x to minutes
                            setTimeout(function (){$("#onetimepassword-wrap").hide()},10000 * 18); //10 seconds(milliseconds) * x to minutes
                            $("#btn-register").attr('data-redirect','/register/resultotp');


                    }
                    }
                });
    };


    ubi.resetPasswordHandler = function($this) {
        ubi.crud.post($this, function(data, textStatus, jqXHR) {
            if (textStatus.toUpperCase() === 'SUCCESS') {
                alertify.success(data.message);
                page.redirect("/login");
            }
        });
    };

    ubi.logout = function($this) {
        var $btn = $($this);            
        ubi.crud.post($this, function() {
            ubi.removeAccess();
            let path = $btn.attr("data-submit");            
            if (path.search("lang=") > 0) {            
              let locale =  path.split("lang=")[1];               
               ubi.goHome(locale);
            }else {
               ubi.goHome();
            }
        });
    };

    // Handle register
    ubi.registerHandler = function($this) {

        ubi.crud.post($this, function(data, textStatus, jqXHR) {
            if (data.code.toUpperCase() === 'SUCCESS') {
                // alertify.success(data.message);
                page.redirect("/login");
            } else {
                alertify.error(data.message, {mode: "notification-error"});
            }
        });

    }

    /*
     * Actions
     */

    /**
     * Function to trigger Signin when a user press enter on password text field
     *
     * @param {type} e
     * @returns {undefined}
     */

    ubi.keyPressedOnLoginPasswordField = function(e) {
        var key = e.keyCode || e.which;
        //On enter pressed send login request
        if (key === 13) {
            ubi.loginHandler($('#btn-login'));
        }
    };

    ubi.keyPressedOnRegisterField = function(e) {
        var key = e.keyCode || e.which;
        //On enter pressed send login request
        if (key === 13) {
            ubi.crud.post($('#btn-register'));
        }
    };

    ubi.keyPressedOnResetPasswordField = function(e) {
        var key = e.keyCode || e.which;
        //On enter pressed send login request
        if (key === 13) {
            ubi.crud.post($('#btn-reset-password'));
        }
    };


})();

