/**
 * Filtering table views
 */

(function (table) {

  "use strict";

  var filter = function ($this) {

    $('html').hasClass('modal') ? ubi.loader.modal.start() : ubi.loader.nonBlocking.start();

    var $this = $($this);

    if ($this.hasClass('loading')) {
      logger.i("CRUD is in use. Please wait.");
      return;
    }

    var formID = $this.attr('form');

    if (formID === undefined) {
      alertify.error(ubi.getTranslationExt("frontend.message.error.1")); // "Something went wrong. Please contact the system administrator"
      throw new TypeError("No form attribute found");
    }

    var $form = $('form#' + formID);
    if ($form.length === 0) {
      throw new TypeError("No form found with id='" + formID + "'");
    }

    var validatorResult = ubi.validator.validate(formID, ajaxFilter, $form.children());
    if (!validatorResult) {
      logger.e("Please check the form fields again");
    }


    function ajaxFilter() {

      $this.addClass('loading');

      // set the ajax url
      var isModal = $('html').hasClass('modal');
      var $dataSubmit = $('#main-area-modal').find('#navigation');
      var urlSubmit = (isModal && $dataSubmit.length > 0) ? $dataSubmit.val() : location.pathname;

      var filtersData = $form.serializeJSON(serializeJSON_OPTIONS);
      var filtersDataTemp = Object.assign({}, filtersData);
      console.log(filtersDataTemp);
      // 'id' in filtersDataTemp ? delete filtersDataTemp.id : null;

      var filtersDataParams = '';
      var filterable = '';

      for (var v in filtersDataTemp) {
        filtersDataParams += v + '=' + filtersDataTemp[v] + '&';
        filterable += v + '|' + filtersDataTemp[v] + '-';
      }

      if (filterable != '') {
        filterable = filterable.slice(0, -1);
        filtersDataParams += 'filterable=' + filterable;        // Always submit the id in order to know when the filters are submitted
      }
      if (filterable==='' && $('#filterable').val()==="-"){
          filtersDataParams = 'filterable=-'
      }

      $.ajax({
        url: urlSubmit,
        type: 'POST',
        data: filtersDataParams
      }).done(function (data, textStatus, jqXHR) {
        setTimeout(function () {
          // console.log(data);
          // TODO - fix selector after testing
          isModal ? $('#mc-inner').html(data) : $('#main-wrapper').children('main').html(data);
          !$('#content-wrapper').hasClass('no-scroll') ? window.scrollTo(0, 0) : null;



          enableSelect2();
          tooltip();


          $('.datepicker').datepicker({
            dateFormat: 'dd/mm/yy',
            locale: 'en',
            changeYear: true,
            changeMonth: true,
            todayHighlight: true,
            yearRange: '1910:2040',
            endDate: new Date(),
            beforeShowDay: function (date) {
              var $this = $(this);
              if (!$this.hasClass('lock-before-today') && !$this.hasClass('enable-today')) {
                var doNothing = true;
                return [doNothing];
              }

              let afterdays = $this.attr("afterdays");
              if (afterdays === undefined || afterdays === '') {
                    afterdays = 0;
              }
              var datepickerString = jQuery.datepicker.formatDate('yy-mm-dd', date);
              var datepickerDate = new Date(datepickerString);
              var today = new Date();
              if ($this.hasClass('enable-today')){
                today.setDate(today.getDate() - 1); 
              }
              today.setDate(today.getDate() + parseInt(afterdays));
              var isGreaterThanToday = datepickerDate.getTime() > today;
              
              return [isGreaterThanToday];
            },
            onClose: function () {
              var $this = $(this);
              $this.parsley().validate();

              // statically added error
              if ($this.hasClass('benderr')) {
                $this.parsley().removeError(this.id);
                $this.removeClass('benderr');
                ubi.var.showErrorsOnTabs();
              }
            }
          });

          enableDropdownLinks();

          isModal ? ubi.loader.modal.stop() : ubi.loader.nonBlocking.stop();
        }, 300);
      });
    }

  };

  table.filter = filter;

})(tb);

/**
 * Sorting js for table list views
 */

(function (table) {

    "use strict";

    var sort = function (param, order) {
        var isModal = $('html').hasClass('modal');
        isModal ? ubi.loader.modal.start() : ubi.loader.nonBlocking.start();
        !$('#content-wrapper').hasClass('no-scroll') ? window.scrollTo(0, 0) : null;

        var pageable = 'sort=' + param + ',' + order;
        var filtersDataParams = '';

        var $this = $('.filter-wrapper').children('form').find('button.tbfilter');
        if ($this.length <= 0) {
          $this = $('.filter-wrapper').find('button.tbfilter');         
        }
        if ($this.length > 0) {
            var formID = $this.attr('form');

            if (formID === undefined) {
                alertify.error(ubi.getTranslationExt("frontend.message.error.1")); // "Something went wrong. Please contact the system administrator"
                throw new TypeError("No form attribute found");
            }

            var $form = $('form#' + formID);
            if ($form.length === 0) {
                throw new TypeError("No form found with id='" + formID + "'");
            }

//            var filtersData = $form.serializeJSON(serializeJSON_OPTIONS);
//            var filtersDataTemp = Object.assign({}, filtersData);
//            for (var v in filtersDataTemp) {
//              filtersDataParams += v + '=' + filtersDataTemp[v] + '&';
//            }

            var $filtersId = $form.find('input#filterable');
            if ($filtersId.length > 0) {
                var filtersIdValue = $filtersId.val();
                var filters = filtersIdValue.split('-');
                filters.forEach(function (filter) {
                    var filtersPair = filter.split('|');
                    if (filtersPair[1] !== undefined){
                      filtersDataParams += filtersPair[0] + '=' + filtersPair[1] + '&';
                    }else{
                      filtersDataParams += filtersPair[0] + '=' + $("#"+filtersPair[0]).val() + '&';
                    }
                });
                filtersDataParams += 'filterable=' + filtersIdValue + '&';
            }
        }

        // set the ajax url

        var $dataSubmit = $('#main-area-modal').find('#navigation');
        var urlSubmit = (isModal && $dataSubmit.length > 0) ? $dataSubmit.val() : location.pathname;

        var postData = filtersDataParams + pageable;

        $.ajax({
            url: urlSubmit,
            type: 'POST',
            data: postData
        }).done(function (data, textStatus, jqXHR) {
            setTimeout(function () {
                isModal ? $('#mc-inner').html(data) : $('#main-wrapper').children('main').html(data);
                enableSelect2();
                tooltip();

                $('.datepicker').datepicker({
                    dateFormat: 'dd/mm/yy',
                    locale: 'en',
                    changeYear: true,
                    changeMonth: true,
                    todayHighlight: true,
                    yearRange: '1910:2040',
                    endDate: new Date(),
                    beforeShowDay: function (date) {
                        var $this = $(this);
                        if (!$this.hasClass('lock-before-today') && !$this.hasClass('enable-today')) {
                            var doNothing = true;
                            return [doNothing];
                        }

                        let afterdays = $this.attr("afterdays");
                        if (afterdays === undefined || afterdays === '') {
                            afterdays = 0;
                        }              
                        var datepickerString = jQuery.datepicker.formatDate('yy-mm-dd', date);
                        var datepickerDate = new Date(datepickerString);
                        var today = new Date();        
                        if ($this.hasClass('enable-today')){
                            today.setDate(today.getDate() - 1); 
                        }
                        today.setDate(today.getDate() + parseInt(afterdays));
                        var isGreaterThanToday = datepickerDate.getTime() > today;
                        return [isGreaterThanToday];
                    },
                    onClose: function () {
                      var $this = $(this);
                      $this.parsley().validate();

                      // statically added error
                      if ($this.hasClass('benderr')) {
                        $this.parsley().removeError(this.id);
                        $this.removeClass('benderr');
                        ubi.var.showErrorsOnTabs();
                      }
                    }
                  });

                enableDropdownLinks();
                isModal ? ubi.loader.modal.stop() : ubi.loader.nonBlocking.stop();
            }, 300);
        });
    };

    table.sort = sort;

})(tb);

