    ubi.checkNotOverlappingTriggeredbyFirstField = function (event, to2, from1, to1) {
        var target = event.target;
        var from2s = target.value;
        var to2s = document.getElementById(to2).value;
        var from1s = document.getElementById(from1).value;
        var to1s = document.getElementById(to1).value;

        if (from1s !== '' && to1s !== '' && from2s !== '' && to2s !== '') {
            //Create dates
            var from1d = createDateFromInput(from1s);
            var to1d = createDateFromInput(to1s);
            var from2d = createDateFromInput(from2s);
            var to2d = createDateFromInput(to2s);
            //console.log('checking ...\n'+from1d+' \n'+to1d+' \n'+from2d+' \n'+to2d);
            if (from1d < to1d && from2d < to2d) {
                //console.log('Checking overlap');
                //Check overlap for from2d
                if (from2d > from1d && from2d < to1d) {
                    resetFieldWithoutMsg(to2);
                    resetFieldWithoutMsg(event.target.id);
                    alertify.error(ubi.getTranslationExt('frontend.error.49')); // 'Date ranges should not overlap'
                    console.log('Overlap found');
                    return;
                }
                //Check overlap for to2d
                if (to2d < to1d && to2d > from1d) {
                    resetFieldWithoutMsg(to2);
                    resetFieldWithoutMsg(event.target.id);
                    alertify.error(ubi.getTranslationExt('frontend.error.49')); // 'Date ranges should not overlap'
                    console.log('Overlap found');
                    return;
                }
            }

        }
    }//EoM

