    function enableHostingEvents() {
        $('#hostingoption').on('change', function (event) {     //$('#maritalstatus')

            var value = event.target.value;
            console.log('Hosting option change:', value);
            var cl = value.toLowerCase().replace(/_/g, '');

            // hide all at first
            $('.parent-fm-wrap').hide();
            // show only the related family member fields
            $('.' + cl).show();

            $('#costoftravling-init-text').hide();
            $('#accommodation-init-text').hide();


            if (value === 'EU_FAMILY_MEMBER') {
                // reset all values on cost of traveling
                resetCostTabAll();
                $('#accommodation-inner').find('.form-control').not('.noreset').val('').trigger('change');
                $('#accommodation-inner').find('.form-control').attr('checked', false);
                //$('#means-support-wrap').hide();
                // hide cost of traveling form if value is EU_FAMILY_MEMBER
                //show no obligation
                $('#costoftravelling-nodrop').removeClass("hidden");
                $('#accommodation-nodrop').removeClass("hidden");
                //hide inner
                $('#costoftravelling-inner').addClass("hidden");
                $('#accommodation-inner').addClass("hidden");
            } else {    //we have obbligation
                //show inner
                $('#costoftravelling-inner').removeClass("hidden");
                $('#accommodation-inner').removeClass("hidden");
                //hide no-obligation
                $('#costoftravelling-nodrop').addClass("hidden");
                $('#accommodation-nodrop').addClass("hidden");
            }

            if (value === 'EU_FAMILY_MEMBER') {
                $('#host1').removeClass("hidden");
                $('#host1').show();
                $('#host2').addClass("hidden");
                $('#host2').hide();
                $('#host2').find('.form-control').not('.noreset').val('').trigger('change');
                $('#host3').addClass("hidden");
                $('#host3').hide();
                $('#host3').find('.form-control').not('.noreset').val('').trigger('change');
                $('#fminvitinganysurname').val('');
                $('#hostingSelectDiv').addClass("hidden");
                $('#accommodationname').val('');

            }

            if (value === 'INVITING_PERSON') {
                if ($('#fminvitinganysurname').val()==='HOTEL OR TEMPORARY ACCOMMODATION'){
                    $('#fminvitinganysurname').val('');
                }
                $('#host2').removeClass("hidden");
                $('#host2').show();
                $('#host1').addClass("hidden");
                $('#host1').hide();
                $('#host1').find('.form-control').not('.noreset').val('').trigger('change');
                $('#host3').addClass("hidden");
                $('#host3').hide();
                $('#host3').find('.form-control').not('.noreset').val('').trigger('change');
                $('#fminvitinganysurname').val('');
                $('#hostingSelectDiv').removeClass("hidden");
                $('#accommodationname').val('');
                $('#accommodationnameDiv').addClass("hidden");


            }

            if (value === 'INVITING_COMPANY') {
                $('#host3').removeClass("hidden");
                $('#host3').show();
                $('#host1').addClass("hidden");
                $('#host1').hide();
                $('#host1').find('.form-control').not('.noreset').val('').trigger('change');
                $('#host2').addClass("hidden");
                $('#host2').hide();
                $('#host2').find('.form-control').not('.noreset').val('').trigger('change');
                $('#fminvitinganysurname').val('');
                $('#hostingSelectDiv').removeClass("hidden");
                $('#accommodationnameDiv').removeClass("hidden");
            }

            if (value === 'HOTEL_TEMP_ACCOMMODATION') {
                $('#host1').addClass("hidden");
                $('#host1').hide();
                $('#host1').find('.form-control').not('.noreset').val('').trigger('change');

                $('#host2').addClass("hidden");
                $('#host2').hide();
                $('#host2').find('.form-control').not('.noreset').val('').trigger('change');

                $('#host3').addClass("hidden");
                $('#host3').hide();
                $('#host3').find('.form-control').not('.noreset').val('').trigger('change');

                //$('#fminvitinganysurname').val('HOTEL OR TEMPORARY ACCOMMODATION');
                $('#hostingSelectDiv').removeClass("hidden");
                $('#accommodationnameDiv').removeClass("hidden");

            }
        });

        $('#fmrelationshiptype').on('change', function (event) {
            var target = event.target;
            var value = target.value;
            //alert(value);
            if (value === '6') {
                $('#divfmrelationshiptypeother').removeClass("hidden");
                $('#divfmrelationshiptypeother').addClass("required");
                $('#divfmrelationshiptypeother').show();
            } else {
                $('#divfmrelationshiptypeother').addClass("hidden");
                $('#divfmrelationshiptypeother').removeClass("required");
                $('#divfmrelationshiptypeother').hide();
                $('#fmrelationshiptypeother').val('');
            }
        });


    }

