    function cleanEUMemberData(isEUMember){
        if (isEUMember){
            //clear employer data
            $('#employername').val('');
            $('#employerstreet').val('');
            $('#employerpostal').val('');
            $('#employercity').val('');

            $('#employercountry').val('');
            $('#employerphonenumberprefix').val('');
            $('#employerphonenumber').val('');

            //clear Cost of Travelling
            $('#costoption').val('');
            if ($( "[id^='meansofsupportlist']" )){
                $.each($( "[id^='meansofsupportlist']" ), function(index, elem){
                    $("#"+elem.id).prop('checked', false);
                });
            }
            $.each($( "[id^='meansofsupportother']" ), function(index, elem){
                $("#"+elem.id).val('');
                $("#div"+elem.id).addClass("hidden");
            });
            $('#meansofsupportothersponsorname').val('');
        }
    }

