    //Calculations
    function createDateFromInput(input) {
        var s = input.split('/'); //split Date of birth dd/MM/yyyy  Days = s[0] | Months = s[1] | Years = s[2]
        //he ISO 8601 syntax (YYYY-MM-DD)
        var newDateofFieldFormat = s[2] + '-' + s[1] + '-' + s[0];
        var dateoffieldDate = new Date(newDateofFieldFormat);
        dateoffieldDate.setHours(0, 0, 0, 0);
        return dateoffieldDate;
    }//EoM

    function dateDiffInYears(dateold, datenew) {
        var ynew = datenew.getFullYear();
        var mnew = datenew.getMonth();
        var dnew = datenew.getDate();
        var yold = dateold.getFullYear();
        var mold = dateold.getMonth();
        var dold = dateold.getDate();
        var diff = ynew - yold;
        if (mold > mnew)
            diff--;
        else {
            if (mold === mnew) {
                if (dold > dnew)
                    diff--;
            }
        }
        return diff;
    }//EoM

    //na dw an mporw na xrhsimopoihsw ayto
    function isAgeLessThan12(dateold, datenew, age) {
        if (age < 12){
          return true;
        }
        if (age > 12){
          return false;
        }
        
        var ynew = datenew.getFullYear();
        var mnew = datenew.getMonth();
        var dnew = datenew.getDate();
        var yold = dateold.getFullYear();
        
        var mold = dateold.getMonth();
        var dold = dateold.getDate();                
        
        if (mold > mnew)
            return true;
        else {
            if (mold === mnew) {
                if (dold >= dnew)
                    return true;
                    
            }
        }
        return false;
    }//EoM


