    function enableLegalGuardianEvents() {
        $('#dateofbirth').on('change', function (event) {
            var datebirth = event.target.value;
            if (datebirth === '') {
                $('#legalguardian-inner').addClass("hidden");
                $('#legalguardian-inner').find('.form-control').val('');
                return;
            }
            var nowDate = new Date();
            var nowplus90 = addDays(nowDate, 90);
            console.log('Date of birth           :' + createDateFromInput(datebirth));
            //console.log('Date in 90 days from now:' + nowplus90);
            //check now + worst case scenario
            /**
             * 29/01/2021 change nowplus90 to nowDate by Ele (email:  [External] FW: Child under 12 issue (22/01/2021))
             */
            var age = dateDiffInYears(createDateFromInput(datebirth), nowDate);//nowplus90); 
            var isLessThan12 = isAgeLessThan12(createDateFromInput(datebirth), nowDate, age); //nowplus90
            console.log('Age: ' + age);            
            if (age >= 18) {
                $('#legalguardian-inner').addClass("hidden");
                $('#legalguardian-inner').find('.form-control').val('');
            } else {
                $('#legalguardian-inner').removeClass("hidden");
                //alertify.success('Legal Guardian fields (Field-10) should be filled', 5);
                //if age <=12 --> set previous fingerprints
                if (isLessThan12){
                    $('#fingerprintscollectedpreviously').val(2); //Not applicable
                    $("#fingerprintscollectedpreviously").trigger('change');
                    $('#fingerprintsexceptionreasontype').val(1); //[A] CHILD UNDER 12 YEARS
                    $("#fingerprintsexceptionreasontype").trigger('change');
                }else{

                }
            }
            //if age> 12 and fingerprintsexceptionreasontype == [A] CHILD UNDER 12 YEARS then remove selection
            if (!isLessThan12 && $('#fingerprintsexceptionreasontype').val() === '1'){
                $("#fingerprintscollectedpreviously option[selected]").removeAttr("selected");
                $("#fingerprintscollectedpreviously")[0].selectedIndex = 0;
                $("#fingerprintscollectedpreviously").trigger('change');

                $("#fingerprintsexceptionreasontype option[selected]").removeAttr("selected");
                $("#fingerprintsexceptionreasontype")[0].selectedIndex = 0;
                $("#fingerprintsexceptionreasontype").trigger('change');
            }

            //check arrival
            var arrivaldate = document.getElementById('intendeddateofarrival').value;
            if (datebirth !== '' && arrivaldate !== '') {
                console.log('Date birth     :' + createDateFromInput(datebirth));
                console.log('Date arrival   :' + createDateFromInput(arrivaldate));
                var age2 = dateDiffInYears(createDateFromInput(datebirth), createDateFromInput(arrivaldate));
                console.log('Age2:' + age2);
                if (age2 >= 18) {
                    $('#legalguardian-inner').addClass("hidden");
                    $('#legalguardian-inner').find('.form-control').val('');
                } else {
                    $('#legalguardian-inner').removeClass("hidden");
                }
            }
        });

        $('#intendeddateofarrival').on('change', function (event) {
            var target = event.target;
            var date2 = target.value;
            var date1 = document.getElementById('dateofbirth').value;
            if (date1 !== '' && date2 !== '') {
                var age = dateDiffInYears(new Date(date1), new Date(date2));
                if (age >= 18) {
                    $('#legalguardian-inner').addClass("hidden");
                } else {
                    $('#legalguardian-inner').removeClass("hidden");
                    //alertify.success('Departure Date(Field 30) automatically adjusted', 5);
                }
            }
        });
    }//EoM

    function formatDate(date) {
        let month = String(date.getMonth() + 1);
        let day = String(date.getDate());
        const year = String(date.getFullYear());
        if (month.length < 2)
            month = '0' + month;
        if (day.length < 2)
            day = '0' + day;
        return `${day}/${month}/${year}`;
    }//EoM

    function addDays(date, days) {
        var result = new Date(date);
        result.setDate(result.getDate() + days);
        return result;
    }//EoM
    
     function date_diff_indays(date1, date2) {
        let dt1 = new Date(date1);
        let dt2 = new Date(date2);
        return Math.floor((Date.UTC(dt2.getFullYear(), dt2.getMonth(), dt2.getDate()) - Date.UTC(dt1.getFullYear(), dt1.getMonth(), dt1.getDate()) ) /(1000 * 60 * 60 * 24));
    }

