    function getLanguage() {
        var language;
        language = getCookie('org.springframework.web.servlet.i18n.CookieLocaleResolver.LOCALE');
        return language;
    }//EoM

    function getCookie(cn) {
        var name = cn + "=";
        var allCookie = decodeURIComponent(document.cookie).split(';');
        var cval = [];
        for (var i = 0; i < allCookie.length; i++) {
            if (allCookie[i].trim().indexOf(name) == 0) {
                cval = allCookie[i].trim().split("=");
            }
        }
        return (cval.length > 0) ? cval[1] : "";
    }//EoM


    function checkNumberWithCountryPrefix(number, prefixcountry) {
        let country = $(prefixcountry).val();
        if (country !== 0 && country !== undefined && country !== '') {
            // Country
            ubi.loader.blocking.start();
            $.get({
                url: "/api/v1/countrytype/" + country,
                contentType: "application/json; charset=utf-8"
            }).done(function (data, status, xhr) {
                if ("SUCCESS" === data.code) {
                    var rcountry = data.returnobject;
                    logger.i("Country loaded successful");
                    //console.log(rcountry.id + "-" + rcountry.name + "(" + rcountry.tellength + "): " + rcountry.telregex);
                    var pattern = rcountry.telregex;
                    var length = rcountry.tellength;
                    if (length == '1-14') {
                        length = 14;
                    }
                    $(number).attr('maxlength', length);
                    $(number).attr('pattern', pattern);
                    $(number).attr('data-parsley-pattern-message', ubi.getTranslationExt('frontend.error.6.1') + " " + length);
                    $(number).trigger("change", true);
                    var element = $(number).parsley();
                    element.reset();
                    // $(number).attr('data-parsley-pattern-message', passportmessage);

                } else {
                    alertify.error(data.message);
                }
                ubi.loader.blocking.stop();
            });
        } else {
            alertify.error(ubi.getTranslationExt('frontend.error.52')); // "Error communicating with server"
        }
    }

