    function setPassportFormat(rcountry){
        var lang = getLanguage();
        if ( rcountry.paasportregex !== null && rcountry.paasportregex.length > 0 ){
                $('<input>').attr({
                    type: 'hidden',
                    id: 'passportregex'+rcountry.id,
                    name: 'passportregex'+rcountry.id,
                    value: rcountry.paasportregex
                }).appendTo('form');
                $('#traveldocumentnumber').attr('pattern', rcountry.paasportregex);
                $('#traveldocumentnumber2').attr('pattern', rcountry.paasportregex);
                let mrzravel = $("#mrztraveldocumentnumber").val();
               // console.log("mrzravel="+mrzravel)
                if (mrzravel !== 0 && mrzravel !== undefined ) {
                    $('#mrztraveldocumentnumber').attr('pattern', rcountry.paasportregex);
                }                        
            }else{
                $('#traveldocumentnumber').removeAttr('pattern');
                $('#traveldocumentnumber2').removeAttr('pattern');
                let mrzravel = $("#mrztraveldocumentnumber").val();
                if (mrzravel !== 0 && mrzravel !== undefined ) {
                    $('#mrztraveldocumentnumber').removeAttr('pattern');
                }
            }
            if ( rcountry.paasportregex !== null && rcountry.paasportregex.length > 0 ){
                $('<input>').attr({
                    type: 'hidden',
                    id: 'passportsize'+rcountry.id,
                    name: 'passportsize'+rcountry.id,
                    value: rcountry.paasportsize
                }).appendTo('form');
                $('#traveldocumentnumber').attr('maxlength', rcountry.paasportsize);
                $('#traveldocumentnumber2').attr('maxlength', rcountry.paasportsize);
                let mrzravel = $("#mrztraveldocumentnumber").val();
                if (mrzravel !== 0 && mrzravel !== undefined ) {                            
                    $('#mrztraveldocumentnumber').attr('maxlength', rcountry.paasportsize);
                }
            }else{
                $('#traveldocumentnumber').removeAttr('maxlength');
                $('#traveldocumentnumber2').removeAttr('maxlength');
                let mrzravel = $("#mrztraveldocumentnumber").val();
                if (mrzravel !== 0 && mrzravel !== undefined ) {                            
                    $('#mrztraveldocumentnumber').removeAttr('maxlength');
                }
            }
            var passportmessage = rcountry.passportmessage;
            if (lang === 'ru-RU')
                passportmessage = rcountry.passportmessageru;
            if (lang === 'am-AM')
                passportmessage = rcountry.passportmessageam;
            if (lang === 'cn-CN')
                passportmessage = rcountry.passportmessagecn;
            if (lang === 'ar')
                passportmessage = rcountry.passportmessagear;
            if (lang === 'ku')
                passportmessage = rcountry.passportmessageku;
            if (lang === 'sr')
                passportmessage = rcountry.passportmessagesr;
            if (lang === 'sq')
                passportmessage = rcountry.passportmessagesq;
            if (lang === 'in')
                passportmessage = rcountry.passportmessagein;

            if (rcountry.paasportregex !== null && rcountry.paasportregex.length > 0){
                $('<input>').attr({
                    type: 'hidden',
                    id: 'passportmessage'+rcountry.id,
                    name: 'passportmessage'+rcountry.id,
                    value: passportmessage
                }).appendTo('form');
                $('#traveldocumentnumber').attr('data-parsley-pattern-message', passportmessage);
                $('#traveldocumentnumber2').attr('data-parsley-pattern-message', passportmessage);
                let mrzravel = $("#mrztraveldocumentnumber").val();
                if (mrzravel !== 0 && mrzravel !== undefined ) {                            
                    $('#mrztraveldocumentnumber').attr('data-parsley-pattern-message', passportmessage);
                }
            }else{
                $('#traveldocumentnumber').removeAttr('data-parsley-pattern-message');
                $('#traveldocumentnumber2').removeAttr('data-parsley-pattern-message');
                let mrzravel = $("#mrztraveldocumentnumber").val();
                if (mrzravel !== 0 && mrzravel !== undefined ) {                            
                    $('#mrztraveldocumentnumber').removeAttr('data-parsley-pattern-message');
                }
            }
    }

