    function changeTravelDocumentIssuingCountry(fieldname){
        let country = $("#"+fieldname).val();
        if (country !== 0 && country !== undefined && country !== '') {
            // Country
            if ($('#passportregex'+country).length){
                $('#traveldocumentnumber').attr('pattern', $('#passportregex'+country).val());
                $('#traveldocumentnumber2').attr('pattern', $('#passportregex'+country).val());
                let mrzravel = $("#mrztraveldocumentnumber").val();
                if (mrzravel !== 0 && mrzravel !== undefined ) {
                    $('#mrztraveldocumentnumber').attr('pattern', $('#passportregex'+country).val());
                }
            }else{
                $('#traveldocumentnumber').removeAttr('pattern');
                $('#traveldocumentnumber2').removeAttr('pattern');
                let mrzravel = $("#mrztraveldocumentnumber").val();
                if (mrzravel !== 0 && mrzravel !== undefined ) {
                    $('#mrztraveldocumentnumber').removeAttr('pattern');
                }
            }
            if ($('#passportsize'+country).length){
                $('#traveldocumentnumber').attr('maxlength', $('#passportsize'+country).val());
                $('#traveldocumentnumber2').attr('maxlength', $('#passportsize'+country).val());
                let mrzravel = $("#mrztraveldocumentnumber").val();
                if (mrzravel !== 0 && mrzravel !== undefined ) {
                    $('#mrztraveldocumentnumber').attr('maxlength', $('#passportsize'+country).val());
                }
            }else{
                $('#traveldocumentnumber').removeAttr('maxlength');
                $('#traveldocumentnumber2').removeAttr('maxlength');
                let mrzravel = $("#mrztraveldocumentnumber").val();
                if (mrzravel !== 0 && mrzravel !== undefined ) {
                    $('#mrztraveldocumentnumber').removeAttr('maxlength');
                }
            }
            if ($('#passportmessage'+country).length){
                $('#traveldocumentnumber').attr('data-parsley-pattern-message', $('#passportmessage'+country).val());
                $('#traveldocumentnumber2').attr('data-parsley-pattern-message', $('#passportmessage'+country).val());
                let mrzravel = $("#mrztraveldocumentnumber").val();
                if (mrzravel !== 0 && mrzravel !== undefined ) {
                    $('#mrztraveldocumentnumber').attr('data-parsley-pattern-message', $('#passportmessage'+country).val());
                }
            }else{
                $('#traveldocumentnumber').removeAttr('data-parsley-pattern-message');
                $('#traveldocumentnumber2').removeAttr('data-parsley-pattern-message');
                let mrzravel = $("#mrztraveldocumentnumber").val();
                if (mrzravel !== 0 && mrzravel !== undefined ) {
                    $('#mrztraveldocumentnumber').removeAttr('data-parsley-pattern-message');
                }
            }


        }
    }

