    function enableVisaTypes(){
        //if visa type exists
        if ($('#visatype').length){
            $("#vac").change(function () {

                let vac = $("#vac").val();
                console.log('vac', vac);
                //fetch choices
                if (vac !== 0 && vac !== undefined && vac !== '') {
                    // vac
                    ubi.loader.blocking.start();
                    $.get({
                        url: "/api/v1/vac/" + vac + "/visatype",
                        contentType: "application/json; charset=utf-8"
                    }).done(function (data, status, xhr) {
                        if ("SUCCESS" === data.code) {
                            logger.i("visatype loaded successful");
                            var lang = getLanguage();
    //                        console.log('lang', lang);
                            var option1 = new Option('', '');
                            //remove all first
                            $('#visatype').find('option').remove();
                            //add new items
                            $('#visatype').append($(option1));

                            $.each(data.returnobject, function (i, rvisatype) {
                                var mlname = rvisatype.name;
                                if (lang === 'ru-RU')
                                    mlname = rvisatype.nameru;
                                if (lang === 'am-AM')
                                    mlname = rvisatype.nameam;
                                if (lang === 'cn-CN')
                                    mlname = rvisatype.namecn;
                                var option2 = new Option(mlname, rvisatype.id);
                                if (data.returnobject.length==1){
                                    option2.selected = 'selected';
                                }
                                $('#visatype').append($(option2));
                            });


                        } else {
                            alertify.error(data.message);
                        }
                        ubi.loader.blocking.stop();
                    });
                }


            });
        }
    }//EoM

