    function confirmSubmission($this, temp, verb, enableConfirm, msgid, formID){
        if (!enableConfirm){
            refreshMRZ();
            let newExtraservicesSer = $('#extraservices :input').serialize();
            if ($($this).attr("id") !== 'btn-newvisa-savepprs' && newExtraservicesSer !== extraservicesSer){                
                financialAlert($this, temp, verb);                
            }else{
                handleCreate($this, temp, verb, false);
            }
        }else{
            //check if checkbox is checked
            if ($('input[name="submitinfo"]:checked').length > 0){

                // Define form
                var $form = $('form#' + formID);
                if ($form.length < 1) {
                  throw new TypeError("No form found with id='" + formID + "'");
                }

                var fields = $form.serializeJSON(serializeJSON_OPTIONS);
                var field;
                for (field in fields) {
                  if (typeof fields[field] === 'string') {
                    fields[field] = fields[field].trim();
                  }
                }


                $.get({
                    url: "/api/v1/var/validate",
                    contentType: "application/json; charset=utf-8",
                    type: 'POST',
                    data: JSON.stringify(fields)
                    }).done(function (data, status, xhr) {                            
                        if ("SUCCESS" === data.code && !Array.isArray(data.returnobject)) {
                            displayConfirmationMessage($this, temp, verb, msgid, true);
                        }else if (Array.isArray(data.returnobject)) {      //Array of errors
                             checkForErrors(data.returnobject);
                        }
                    });
            }else{
                //force to check the checkbox
                var msgCheck = $("#"+msgid+"Check").val();
                alertify.error(msgCheck);
            }


        }//end of else
    }//EoM

