    function refreshMRZ(){
        if ($( "input[id^='mrz']" )){
            $.each($( "input[id^='mrz']" ).not("mrztraveldocumentnumber"), function(index, elem){
                let formfieldname = elem.id.substr(3);
                let formfield = $( "#"+formfieldname);
                if (formfield && formfield.length && formfield.length > 0 && elem.value !== formfield.val()){
                    elem.value = formfield.val();
                }
            });
            $.each($( "input[id^='mrz']" ).not("mrztraveldocumentnumber"), function(index, elem){

                var parelem = $('#traveldocumentnumber').parsley();
                var parelem2 = $('#traveldocumentnumber2').parsley();
                var parelem3 = $('#mrztraveldocumentnumber').parsley();
                parelem.reset();
                parelem2.reset();
                parelem3.reset();

                let formfieldname = elem.id.substr(3);
                let formfield = $( "#"+formfieldname);
                if (formfield && formfield.length && formfield.length > 0 && elem.value !== formfield.val()){
                    elem.value = formfield.val();
                }

            });

        }
        if ($( "select[id^='mrz']" )){
            $.each($( "select[id^='mrz']" ).not("mrztraveldocumentissuingcountry"), function(index, elem){
                let formfieldname = elem.id.substr(3);
                let formfield = $( "#"+formfieldname);
                if (formfield && formfield.length && formfield.length > 0 && elem.value !== formfield.val()){
                    elem.value = formfield.val();
                    $('#'+elem.name).trigger('change', true);
                }
                if (formfieldname==='mrzcurrentnationality1'){
                    setCurrentNationalityPassport1();
                }
            });
            $("#mrztraveldocumentissuingcountry").change(function () {
                changeTravelDocumentIssuingCountry("mrztraveldocumentissuingcountry");
            }); //mrztraveldocumentissuingcountry
        }
    }


