    var extraservicesSer = "";

    function onFieldFocus() {
        function removeErrors() {
            var $this = $(this);
            if ($this.hasClass('benderr')) {
                $this.parsley().removeError(this.id);
                $this.removeClass('benderr');
                showErrorsOnTabs();
            }
        }

        $('#visa-request').find('.form-control').on('keydown', removeErrors);

        $('#visa-request').find('.form-control').on('select2:select', removeErrors);
    }
    
    //clear all previous errors
    function removeAllErrors(){
      $('#form-tabs li').each(function (i, v) {        
            var $this = $(this);
            var tabId = v.id;
            var tabContentId = tabId.split('-')[1];

            $('#' + tabContentId).each(function (i2, v2) {
                var $tabContent = $(v2);    
                           
                $tabContent.find('.parsley-errors-list.filled').each(function (i1, v1) {                
                  v1.remove();
                });
                $this.children('.errors-num').text('');                
            })
        });
        
    }

    // show error number indicators on tabs
    function showErrorsOnTabs() {
        $('#form-tabs li').each(function (i, v) {
            var $this = $(this);
            var tabId = v.id;
            var tabContentId = tabId.split('-')[1];

            $('#' + tabContentId).each(function (i, v) {
                var $tabContent = $(v);
                var errorsNum = $tabContent.find('.parsley-errors-list.filled').length;

                if (errorsNum > 0) {
                    $this.children('.errors-num').text(errorsNum);
                } else {
                    $this.children('.errors-num').text('');
                }
            })
        })
    }

    function handleCreate($this, temp, verb, isApplicant) {
        removeAllErrors();
        
        var $this = $($this);
        var formID = $this.attr('form');
        var $form = $('#' + formID);
        //TODO for immediate return in case of non existing of mandatory
        $form.parsley().reset();
        resetErrorsOnTabs();
        var dataRedirectArray = $this.attr('data-redirect').split("/");
        //add hash only in case of edit and add
        if (window.location.hash.length>0 && $this.attr('data-redirect')!=="stay"
                && ($this.attr('data-redirect').indexOf('/group/')< 0 &&
                    $this.attr('data-redirect').indexOf('/result/')< 0
                ) &&
                (dataRedirectArray.length>0&& !isNaN(dataRedirectArray[dataRedirectArray.length-1]))){
            if (!$this.attr('data-redirect-origin')){
                $this.attr('data-redirect-origin', $this.attr('data-redirect'));
            }
            var dataRedirect = $this.attr('data-redirect-origin');
            if (!dataRedirect.endsWith("/")){
                dataRedirect = dataRedirect + "/";
            }
            $this.attr('data-redirect', dataRedirect + window.location.hash.split("#")[1]);

        }
        
        var originDataRedirect = $this.attr('data-redirect');
        //when the below code is acitve, user didn't redirect after (save draft -> submit) and all buttons goes to page not found.
        // if (isApplicant) {
        //   $this.attr('data-redirect', 'stay');
        // }
        ubi.crud[verb]($this, function (data) {
            if (isApplicant){
              $this.attr('data-redirect', originDataRedirect);
            }
            var robj = data.returnobject;
            if (Array.isArray(robj)) {      //Array of errors              
                //checkForErrors(robj);
                if (checkForErrors(robj)) {
                    console.log("errors");
                    document.documentElement.scrollTop = 0;
                }
            } else if ($this.attr('data-redirect').indexOf('/result/0')>= 0){
                $this.attr('data-redirect', '/visa-request/result/' + robj);
                page('/visa-request/result/' + robj);
            } else if (!isNaN(robj) && robj > 0 && temp) {
                page('/visa-request/' + robj); //+ window.location.hash
            }

        }, {skipValidation: temp}); // if true skip validation

    }
    
