    function loadAndPreviewPhoto() {
        var varid = $('#id').val();
        var API_URL = ubi.API_URL_PREFIX + "/var/" + varid + "/dophotopreview";

        // todo extra checks for other users
        $.ajax({
            type: 'GET',
            url: API_URL,
            processData: false,
            contentType: false
        }).done( function (data, textStatus, jqXHR) {
            console.log("Status: " + textStatus + ", code: " + jqXHR.status);
            $("#photodiv").html('<img id="photo" src="data:image/jpg;base64,' + data + '" />');
            // $('#photofile').attr('src', "data:image/jpg;base64,' + data + '");
        }).error(function (data, textStatus, jqXHR) {
            console.log("Status: " + textStatus + ", code: " + jqXHR.status);
            // alertify.error("No photo exists for this application")
            $("#photodiv").html('<img id="photo" src="/dist/images/photo.jpg" />');
        });
    }

