/**
 * Exporter wrapper
 */

(function () {

  'use strict';

  var exporter = {
      exportfile: exportfile,
      exportfilebatch: exportfilebatch
      
  };
  
  
  

  function exportfile(btn, dataSubmit, dataRedirect, callback) {

    var data = $('#appids').val();
    data = data.toUpperCase();
    // match all valid application ids and remove duplicates
    //var matched = data.match(/[A-Z]{5}-[A-Z]{2}[\d]{7}/gm);
    var matched = data.match(/(([A-Z])|(\d)|(-)){15}|[A-Z]{4}[\d]{10}/gm);    
    if (matched === null) {
      alertify.error(ubi.getTranslationExt("frontend.message.error.11"), 10); //"No proper Application IDs found!"
      return;
    } else {
      var result = matched.filter((word, i, arr) => arr.indexOf(word) === i);
      var numVars = result.length;
      $('#appids').val(result.join('\n') + '\n');// add a newline to allow the user to resume scanning seamlessly
      $('#numOfUniqueRecords').text(numVars);
    }

    // varcommon.filterMultipleAppIDs();
      // Define API
      var API_URL;
      if (dataSubmit !== undefined && dataSubmit
          != "" && dataSubmit != null) {
        API_URL = ubi.API_URL_PREFIX + dataSubmit;
      } else {
        throw new TypeError("'data-submit' attribute couldn't be found.");
      }

      var ajaxOptions = {
        url: API_URL,
        type: 'post'
      };


      var $this = $(btn);
      var formID = $this.attr('form'); //TODO - Check form attribute in old browsers (check in IE11 - passed)

      var hasForm = (formID !== undefined && formID != "") ? true : false;

      if (hasForm) {
        // Define form
        var $form = $('form#' + formID);

        if ($form.length < 1) {
          throw new TypeError("No form found with id='" + formID + "'");
        }

        var fields = $form.serializeJSON(serializeJSON_OPTIONS);
        var field;
        for (field in fields) {
          if (typeof fields[field] === 'string') {
            fields[field] = fields[field].trim();
          }
        }

        ajaxOptions.data = JSON.stringify(fields);
        ajaxOptions.contentType = "application/json; charset=utf-8";
      }
      
      exportProcedure(dataRedirect, ajaxOptions, callback)
  };
  
  function exportfilebatch(btn, formID, dataSubmit, dataRedirect, callback) {
	
    var hasForm = (formID !== undefined && formID != "") ? true : false;
      // Define API
      var API_URL;
      if (dataSubmit !== undefined && dataSubmit
          != "" && dataSubmit != null) {
        API_URL = ubi.API_URL_PREFIX + dataSubmit;
      } else {
        throw new TypeError("'data-submit' attribute couldn't be found.");
      }

      var ajaxOptions = {
        url: API_URL,
        type: 'post'
      };
      
      if (hasForm) {
        // Define form
        var $form = $('form#' + formID);
        if ($form.length < 1) {
          throw new TypeError("No form found with id='" + formID + "'");
        }
        
        var fields = $form.serializeJSON(serializeJSON_OPTIONS);
        var field;
        for (field in fields) {
          if (typeof fields[field] === 'string') {
            fields[field] = fields[field].trim();
          }
        }

        ajaxOptions.data = JSON.stringify(fields);
        console.log(ajaxOptions.data);
        ajaxOptions.contentType = "application/json; charset=utf-8";
        console.log(ajaxOptions);
      }

      exportProcedure(dataRedirect, ajaxOptions, callback);
  };
  
    var myVar;    
    function showTime(){
        var d = new Date();
        var t = d.toLocaleTimeString();
        $("#loaderMsgCounter").html(t); // display time on the page
    }
    function stopFunction(){
        clearInterval(myVar); // stop the timer
    }
    
  function preventClose(e){       
    return "Sure you want to leave?";        
  }
  
  function addLoadMessage(){
      var newRow = '<div class="tr" id="loaderMsg" style="z-index: 11;position: absolute;margin-top: 260px; left: 40%; width: 460px; height: 160px; margin-left: -30px;">'+
                     ubi.getTranslationExt("frontend.message.donotclosebrowser")+ // Please wait and do not close the browser or refresh the page!!!
                    '<div style="padding-top:10px;padding-left:10px" id="loaderMsgCounter"></div>'+
                    '</div>';
      $('.loader').after(newRow);
      showTime();
      myVar = setInterval(showTime, 1000);    
     // window.addEventListener('beforeunload', preventClose);
     // console.log("add");
  }
  
  function removeLoadMessage(){      
      $('#loaderMsg').remove();
      stopFunction();
     // window.removeEventListener('beforeunload', preventClose);
     // console.log("remove");
  }
  
  function exportProcedure(dataRedirect, ajaxOptions, callback){
      // Start CRUDer
      $('body').addClass('loading');
      addLoadMessage();
      
      
      var customRedirect;
      customRedirect = dataRedirect !== 'undefined'
        && dataRedirect !== "" ? dataRedirect : undefined;

      $.ajax(ajaxOptions).done(function (data, textStatus, jqXHR) {
        // tb.filter($("#btn-filter-var"));
        //Check if the new record is created
        if (textStatus.toUpperCase() == "SUCCESS" && (data == "" || data === undefined || data.code.toUpperCase() === "SUCCESS")) {
          setTimeout(function () {
              
            if (data && data.returnobject && data.returnobject.fileName){
                var downloadUrl = '/download/'+data.returnobject.fileName+'/file/'+data.returnobject.fileDownloadUri;
                if (data.returnobject.repository && data.returnobject.repository !== "" && data.returnobject.repository !== undefined){
                    downloadUrl = '/download/'+data.returnobject.fileName+'/b/'+data.returnobject.repository+"/"+data.returnobject.fileDownloadUri;
                }
                console.log(downloadUrl);
                window.open(downloadUrl);
            }

            data != "" && "message" in data && data.message != null
                ? alertify.success(data.message, 20)
                : null;

            // Remove loader
            removeLoadMessage();
            $('body').removeClass('loading');

            /*if (typeof callback === 'function') {

              callback(data, textStatus, jqXHR);

            }*/

          }, ubi.loader.blocking.loadingTime);
        } else {
          "message" in data ? alertify.error(data.message) : alertify.error(
              ubi.getTranslationExt("frontend.message.error.1")) ;// "Something went wrong. Please contact the system administrator.")
          removeLoadMessage();
          $('body').removeClass('loading');
        }

        if (typeof callback === 'function') {

          callback(data, textStatus, jqXHR);

        }
      }).fail(function (jqXHR, textStatus, errorThrown) {
        "responseJSON" in jqXHR && "message" in jqXHR.responseJSON
            ? alertify.error(jqXHR.responseJSON.message) : alertify.error(
            ubi.getTranslationExt("frontend.message.error.2")) ;// "Something went wrong. Try again later."
        removeLoadMessage();
        $('body').removeClass('loading');
      });
  }
    
  window.exporter = exporter;

})(window);

/**
 * Add/Remove vars in a group
 */

(function (window) {

    'use strict';

    var groupedit = {
        singleRemove: singleRemove,
        multiRemove: multiRemove,
        removeFromGroup: removeFromGroup,
        singleAdd: singleAdd,
        multiAdd: multiAdd,
        addInGroup: addInGroup
    };

    function singleRemove(btnid, varid) {
        removeFromGroup(btnid, varid);
    }

    function multiRemove(btnid) {
        var selected = new Array();
        $('input[name=selectvar]:checked').each(function () {
            selected += $(this).val()+",";
        });
        removeFromGroup(btnid, selected);
    }

    function removeFromGroup(btnid, selected) {
        var $btn = $("#" + btnid);
        alertify.confirm(ubi.getTranslationExt('frontend.message.group.remove.title'), ubi.getTranslationExt('frontend.message.group.remove.message'),
            innerCrud,
            function(){                
                alertify.alert(ubi.getTranslationExt('frontend.message.group.remove.title'), ubi.getTranslationExt('frontend.message.group.remove.cancelled'));
            }
        ).set({
            labels: {ok: ubi.getTranslationExt('frontend.message.group.remove.submit'), cancel: ubi.getTranslationExt('frontend.message.group.remove.cancel')},           
            reverseButtons: true,
            transition: 'fade'
        });
        function innerCrud() {
            var API_URL = ubi.API_URL_PREFIX + $btn.attr("data-submit");
            var redirect = $btn.attr('data-redirect');

            var varsData = new FormData();
            varsData.append('varids', selected);

            $btn.addClass('loading');

            $.ajax({
                type: 'POST',
                data: varsData,
                url: API_URL,
                processData: false,
                contentType: false
            }).done(function (data, textStatus, jqXHR) {
                if (textStatus.toUpperCase() == "SUCCESS") {
                    page(redirect);
                    if (data.code.toUpperCase() === "SUCCESS") {
                        alertify.success(data.message);
                    } else if (data.code.toUpperCase() === "INVALID") {
                        alertify.message(data.message + data.returnobject,20);
                    }
                } else {
                    "message" in data ? alertify.error(data.message) : alertify.error(ubi.getTranslationExt("frontend.message.error.1")); // "Something went wrong. Please contact the system administrator."
                }
            }).error(function (data, textStatus, jqXHR) {
                alertify.error(ubi.getTranslationExt("frontend.message.error.5")); // "Please contact the system administrator"
            });

            $btn.removeClass('loading');
        };
    };

    function singleAdd(btnid, varid) {
        addInGroup(btnid, varid);
    };

    function multiAdd(btnid) {
        var selected = new Array();
        $('input[name=selectvar]:checked').each(function () {
            selected += $(this).val()+",";
        });
        addInGroup(btnid, selected);
    };

    function addInGroup(btnid, selected) {
        var $btn = $("#" + btnid);
        alertify.confirm(ubi.getTranslationExt('frontend.message.group.add.title'), ubi.getTranslationExt('frontend.message.group.add.message'),
            innerCrud,
            function(){                
                alertify.alert(ubi.getTranslationExt('frontend.message.group.add.title'), ubi.getTranslationExt('frontend.message.group.add.cancelled'));
            }
        ).set({
            labels: {ok: ubi.getTranslationExt('frontend.message.group.add.submit'), cancel: ubi.getTranslationExt('frontend.message.group.add.cancel')},
            reverseButtons: true,
            transition: 'fade'
        });
        function innerCrud() {
            var API_URL = ubi.API_URL_PREFIX + $btn.attr("data-submit");
            var redirect = $btn.attr('data-redirect');

            var varsData = new FormData();
            varsData.append('varids', selected);

            $btn.addClass('loading');

            $.ajax({
                type: 'POST',
                data: varsData,
                url: API_URL,
                processData: false,
                contentType: false
            }).done(function (data, textStatus, jqXHR) {
                if (textStatus.toUpperCase() == "SUCCESS") {
                    page(redirect);
                    if (data.code.toUpperCase() === "SUCCESS") {
                        alertify.success(data.message);
                    } else if (data.code.toUpperCase() === "INVALID") {
                        alertify.message(data.message + data.returnobject,20);
                    }
                } else {
                    "message" in data ? alertify.error(data.message) : alertify.error(ubi.getTranslationExt("frontend.message.error.1")); //"Something went wrong. Please contact the system administrator."
                }
            }).error(function (data, textStatus, jqXHR) {
                alertify.error(ubi.getTranslationExt("frontend.message.error.5")); // "Please contact the system administrator"
            });

            $btn.removeClass('loading');
        };
    };

    window.groupedit=groupedit;

})(window);

