(function () {

    'use strict';

    function confirmPeriodEdit($this, action) {
        var title = $("#" + action + "PopupTitle").val();
        var msg = $("#" + action + "PopupMsg").val();

        alertify.confirm(title, msg,
            function() {
                if (action == "put") {
                    ubi.crud.put($this);
                }
                /*else if (action == "delete") {
                    console.log("to delete period");
                    ubi.crud.delete($this);
                }*/
            },
            function () {
                logger.i("Action cancelled");
            }
        ).set({
            labels: {ok: ubi.getTranslationExt('frontend.message.generic.ok'), cancel: ubi.getTranslationExt('frontend.message.generic.cancel')},
            reverseButtons: true,
            transition: 'fade'
        });
    }

    function confirmPeriodAction($this, action, prompt) {

        var $btn = $($this);
        var title = $("#" + action + "PopupTitle").val();
        var msg = $("#" + action + "PopupMsg").val();

        var $this = $($this);

        var formID = $this.attr('form'); //TODO - Check form attribute in old browsers (check in IE11 - passed)

        var hasForm = (formID !== undefined && formID != "") ? true : false;

        let moreHolidays = false;
        if ($('#moreHolidays').val() !== undefined && $('#moreHolidays').val() != ""){
            moreHolidays = ($('#moreHolidays').val() === 'true' );
        }
        console.log($this.attr('data-submit'));
        console.log($this.attr('data-submit').indexOf("check"));

        // the prompt should show:
        // only when it is not a "check" request AND
        // if the flag is explicitly set to true OR there are holidays in vac/country
        if ((moreHolidays || prompt) && $this.attr('data-submit').indexOf("check") < 0 ){
        alertify.confirm(title, msg,
            innerCrud,
            function () {
                    alertify.alert(ubi.getTranslationExt('frontend.message.cancelled.title'), ubi.getTranslationExt('frontend.message.cancelled.msg'));
            }
        ).set({
                labels: {ok: ubi.getTranslationExt('frontend.message.generic.proceed'), cancel: ubi.getTranslationExt('frontend.message.generic.cancel')},
            reverseButtons: true,
            transition: 'fade'
        });
        }else{
            innerCrud();
        }

        function innerCrud() {  // copied from crud.js
            // Define API
            var API_URL;
            if ($this.attr('data-submit') !== undefined && $this.attr('data-submit')
                != "" && $this.attr('data-submit') != null) {
                API_URL = ubi.API_URL_PREFIX + $this.attr('data-submit');
            } else {
                throw new TypeError("'data-submit' attribute couldn't be found.");
            }

            var ajaxOptions = {
                url: API_URL,
                type: action
            };

            if (hasForm) {
                // Define form
                var $form = $('form#' + formID);
                if ($form.length < 1) {
                    throw new TypeError("No form found with id='" + formID + "'");
                }

                var fields = $form.serializeJSON(serializeJSON_OPTIONS);
                var field;
                for (field in fields) {
                    if (typeof fields[field] === 'string') {
                        fields[field] = fields[field].trim();
                    }
                }

                ajaxOptions.data = JSON.stringify(fields);
                ajaxOptions.contentType = "application/json; charset=utf-8";
            }

            // Start CRUDer
            $this.addClass('loading');

            var customRedirect;
            customRedirect = $this.attr('data-redirect') !== 'undefined'
            && $this.attr('data-redirect') !== "" ? $this.attr('data-redirect') : undefined;

            $.ajax(ajaxOptions).done(function (data, textStatus, jqXHR) {
                //Check if the new record is created
                if (textStatus.toUpperCase() == "SUCCESS" && (data == "" || data === undefined || data.code.toUpperCase() === "SUCCESS")) {
                    setTimeout(function () {

                        var redirectURL;
                        var pathname = window.location.pathname + window.location.search;

                        if (typeof customRedirect !== 'undefined' && typeof customRedirect === 'string') {
                            redirectURL = customRedirect;
                        } else if ("returnobject" in data && typeof data.returnobject === 'object'
                            && data.returnobject != null && "redirectURL" in data.returnobject) {
                            redirectURL = data.returnobject.redirectURL;
                        } else {
                            // Initialize redirect URL. By default it reloads current page
                            redirectURL = pathname;
                        }

                        // Inform user
                        logger.i("Successful API communication at \"" + API_URL
                            + "\" using method " + action);

                        data != "" && "message" in data && data.message != null
                            ? alertify.success(data.message)
                            : null;

                        // Remove loader
                        $this.removeClass('loading');

                        if (data && data.returnobject) {
                            var robj = data.returnobject;
                            var bucketName = "/b/excels";
                            setTimeout(function() {
                                window.open('/download/' + robj.fileName + bucketName + '/' + robj.fileDownloadUri);
                            }, 2000);
                        } else {
                        }

                        // Redirection
                        if (window.location.search.indexOf('redirect=') !== -1) {
                            window.history.back();
                        } else {
                            redirectURL != "stay" ? page(redirectURL) : null;
                        }

                        /*if (typeof callback === 'function') {

                          callback(data, textStatus, jqXHR);

                        }*/

                    }, ubi.loader.blocking.loadingTime);
                } else {
                    "message" in data ? alertify.error(data.message) : alertify.error(
                        ubi.getTranslationExt("frontend.message.error.1")); //"Something went wrong. Please contact the system administrator."
                    $this.removeClass('loading');
                }

                if (typeof callback === 'function') {

                    callback(data, textStatus, jqXHR);

                }
            }).fail(function (jqXHR, textStatus, errorThrown) {
                "responseJSON" in jqXHR && "message" in jqXHR.responseJSON
                    ? alertify.error(jqXHR.responseJSON.message) : alertify.error(
                    ubi.getTranslationExt("frontend.message.error.2")); //"Something went wrong. Try again later."
                $this.removeClass('loading');
            });
        }//End of inner function
    }

    window.confirmPeriodAction = confirmPeriodAction;

})();

