(function () {

    'use strict';

    var varcommon = {
        filterMultipleAppIDs: filterMultipleAppIDs,
        clearAppIDs: clearAppIDs,
        loadTravelAgent: loadTravelAgent,
        loadVacByCountry: loadVacByCountry,
        filtervar: filtervar
    };

    function filterMultipleAppIDs() {
        var data = $('#appids').val();
        data = data.toUpperCase();
        // match all valid application ids and remove duplicates
        // todo edge case where all are wrong => .filter throws error
        //var matched = data.match(/[A-Z]{5}-[A-Z]{2}[\d]{7}/gm);
        var matched = data.match(/(([A-Z])|(\d)|(-)){15}|[A-Z]{4}[\d]{10}/gm);
        if (matched === null) {
            alertify.error(ubi.getTranslationExt("frontend.message.error.11"), 10); //"No proper Application IDs found!"
            return;
        } else {
            var result = matched.filter((word, i, arr) => arr.indexOf(word) === i);
            var numVars = result.length;
            $('#appids').val(result.join('\n') + '\n');// add a newline to allow the user to resume scanning seamlessly
            $('#numOfUniqueRecords').text(numVars);
        }
    };


    function clearAppIDs() {
        // clear text area and zero the counter
        $('#appids').val('');
        $('#numOfUniqueRecords').text(0);
    };
    
    function loadTravelAgent(){
        let travelagent = $("#travelagent").val();
        if (travelagent !== 0 && travelagent !== undefined && travelagent !== ''
                && $("#groupid")!=null && $("#groupid").length) {                        
            ubi.loader.blocking.start();
            let apiUrl = "/api/v1/travelagent/" + travelagent + "/group";                   

            $.get({
                url: apiUrl,
                contentType: "application/json; charset=utf-8"
            }).done(function (data, status, xhr) {
                if ("SUCCESS" === data.code) {

                    logger.i("Info loaded successful");
                    $("#groupid").removeAttr("disabled");
                    var array = data.returnobject;
                    var htmlVar = "";
                    htmlVar += '<option value=""></option>'
                    for (var i = 0; i < array.length; i++) {
                        htmlVar += '<option value="' + array[i].id + '">'
                                + array[i].name
                                + '</option>';
                    }
                    $("#groupid").html(htmlVar);                    
                } else {
                    alertify.error(data.message);
                }
            }); //done
        }
    }
    
    function loadVacByCountry(){
        let country = $("#country").val();
        if (country !== 0 && country !== undefined && country !== ''
                && $("#vac")!=null && $("#vac").length) {                        
            ubi.loader.blocking.start();
            let apiUrl = "/api/v1/country/" + country + "/vac";                 

            $.get({
                url: apiUrl,
                contentType: "application/json; charset=utf-8"
            }).done(function (data, status, xhr) {
                if ("SUCCESS" === data.code) {

                    logger.i("Info loaded successful");
                    $("#vac").removeAttr("disabled");
                    var array = data.returnobject;
                    var htmlVar = "";
                    htmlVar += '<option value=""></option>'
                    for (var i = 0; i < array.length; i++) {
                        htmlVar += '<option value="' + array[i].id + '">'
                                + array[i].shortname
                                + '</option>';
                    }
                    $("#vac").html(htmlVar);                    
                } else {
                    alertify.error(data.message);
                }
            }); //done
        }
    }
    
    
    
    function filtervar($this){
        filterMultipleAppIDs();        
        tb.filter($this);
    }

    window.varcommon = varcommon;

})(window);
