(function () {

    'use strict';    
    
    function onChangeCountry() {
      
        ubi.languageSelector.addEvents();
        enableSelect2();
        selectCountry();
        enableCAPTCHA();

        $("#country").change(function () {
            selectCountry();
        });

    }//EoM onChangeCountry
    
    function selectCountry(){
        
        let country = $("#country").val();
        if (country !== 0 && country !== undefined && country !== '') {
            // Country
            ubi.loader.blocking.start();
            
            $.get({
                url: "/api/v1/country/vac/"+country,
                contentType: "application/json; charset=utf-8"
            }).done(function (data, status, xhr) {
                if ("SUCCESS" === data.code) {
                    logger.i("Info loaded successful");
                    $("#vac").removeAttr("disabled");
                    var array = data.returnobject;
                    var htmlVar = "";
                    htmlVar += '<option value=""></option>'
                    for (var i = 0; i < array.length; i++) {
                        htmlVar += '<option value="' + array[i].id + '">'
                                + array[i].name
                                + '</option>';
                    }
                    $("#vac").html(htmlVar);

                } else {
                    alertify.error(data.message);
                }
            }); //done

            //check validation user type, sms or email
            $.get({
                url: "/api/v1/country/validationtype/"+ country,
                contentType: "application/json; charset=utf-8"
            }).done(function (data, status, xhr) {
                if ("SUCCESS" === data.code) {
                    logger.i("Info loaded successful");

                    var array = data.returnobject;
                    for (var i = 0; i < array.length; i++) {
                            var validationtype = array[0].value;
                            if(validationtype === "false"){
                                $("#btn-register").hide();
                                $("#recaptcha").hide();
                                $("#onetimepassword-wrap").hide();
                                $("#btn-onetimepassword").show();
                            }else{
                                $("#btn-register").show();
                                $("#recaptcha").show();
                                $("#onetimepassword-wrap").hide();
                                $("#btn-onetimepassword").hide();
                            }
                    }
                } else {
                    alertify.error(data.message);
                }
            }); //done

            $.get({
                url: "/api/v1/country/languages/"+ country,
                contentType: "application/json; charset=utf-8"
            }).done(function (data, status, xhr) {
                if ("SUCCESS" === data.code) {
                    logger.i("Info loaded successful");
                    $("#language").removeAttr("disabled");
                    var array = data.returnobject;
                    var htmlVar = "";
                    var selectedLang = '';
                    if ($("#language").attr('sel_lan')){
                        selectedLang = $("#language").attr('sel_lan');
                    }

                  //  htmlVar += '<option value=""></option>'
                    for (var i = 0; i < array.length; i++) {
                        let selectOption = '';
                        if (selectedLang === array[i].id){
                            selectOption = ' selected ';
                        }
                        htmlVar += '<option '+selectOption+' value="' + array[i].id + '">'
                                + array[i].value
                                + '</option>';
                    }
                    $("#language").html(htmlVar);

                } else {
                    alertify.error(data.message);
                }
            }); //done

        }
    }
    
    function uploadOfflineConfig() {
        var input = document.getElementById('configFile');
        var $btn = $('#btn-config');
        var file = input.files[0];

        var reqData = new FormData();
        reqData.append('configFile', file);        
        reqData.append('country', $('#country').val());
        reqData.append('vac', $('#vac').val());

        $btn.addClass('loading');
        $("body").addClass('loading');
        var API_URL = ubi.API_URL_PREFIX + $btn.attr('data-submit');
        
        $.ajax({
            type: 'POST',
            data: reqData,
            url: API_URL,
            processData: false,
            contentType: false
        }).done(function (data, textStatus, jqXHR) {
            if (textStatus.toUpperCase() == "SUCCESS" && data.code.toUpperCase() === "SUCCESS") {
              setTimeout(function () {
                $btn.removeClass('loading');
                $('body').removeClass('loading');

                var redirect = $btn.attr('data-redirect');
                var redirectURL = redirect;


                data != "" && "message" in data && data.message != null
                    ? alertify.success(data.message)
                    : null;


                // Redirection
                if (window.location.search.indexOf('redirect=') !== -1) {
                  window.history.back();
                } else {
                 redirectURL != "stay" ? page(redirectURL) : null;
                }
            }, ubi.loader.blocking.loadingTime);
          }else{
            alertify.error(data.message);
            $btn.removeClass('loading');
            $('body').removeClass('loading');
          }
                        
        }).error(function (data, textStatus, jqXHR) {
            logger.e(textStatus);
            logger.e(data);
            "message" in data ? alertify.error(data.message) : alertify.error(
                    ubi.getTranslationExt("frontend.message.error.1")); //"Something went wrong. Please contact the system administrator."
            //alertify.error(ubi.getTranslationExt("frontend.message.error.5")); // "Please contact the system administrator"

            $btn.removeClass('loading');
            $('body').removeClass('loading');
        });
    }
    
    function setupChangeCountry(){
      selectCountry();
    }
    
    function loadLogin(){
      ubi.languageSelector.addEvents();
      enableCAPTCHA();
    }


    function hideShowFields(){
        loadLogin()
        $("#email").on("input",function(){
            var email = $("#email").val();
            if(email){
                $("#username").hide();
            }else{
                $("#username").show();
            }
        })

        $("#username").on("input",function(){
                    var username = $("#username").val();
                    if(username){
                        $("#email").hide();
                    }else{
                        $("#email").show();
                    }

                })
    }

    function sendOtp(){
        onChangeCountry();
    }


    router.addRouteAnonymousPost('login', loadLogin);
    router.addRouteAnonymousPost('login/:destination', loadLogin);
    router.addRouteAnonymousPost('login/:country/:language', loadLogin);
    router.addRouteAnonymousPost('register', sendOtp);
    router.addRouteAnonymousPost('register/:country/:language', sendOtp);
    router.addRouteAnonymousPost('register/result');
    router.addRouteAnonymousPost('register/resultotp');
    router.addRouteAnonymousPost('resetpassword', hideShowFields);
    router.addRouteAnonymousPost('validation/success');
    router.addRouteAnonymousPost('validation/failure');
    router.addRouteAnonymousPost('validation/already');
    router.addRouteAnonymousPost('resetpassword/**', hideShowFields);

    window.uploadOfflineConfig = uploadOfflineConfig;    
    window.setupChangeCountry = setupChangeCountry;

})();

