(function () {

    'use strict';

    function onEventsForServiceOffering() {
        //-----1 Event-----------
        $("#country").change(function () {
            let country = $("#country").val();
            if (country !== 0 && country !== undefined && country !== '') {
                // Country
                ubi.loader.blocking.start();
                //-------1st call
                $.get({
                    url: "/api/v1/country/" + country + "/vac",
                    contentType: "application/json; charset=utf-8"
                }).done(function (data, status, xhr) {
                    if ("SUCCESS" === data.code) {
                        logger.i("Info loaded successful");
                        //$("#vac").removeAttr("disabled");
                        var array = data.returnobject;
                        var htmlVar = "";
                        htmlVar += '<option value=""></option>'
                        for (var i = 0; i < array.length; i++) {
                            htmlVar += '<option value="' + array[i].id + '">'
                                    + array[i].shortname
                                    + '</option>';
                        }
                        $("#vac").html(htmlVar);
                    } else {
                        alertify.error(data.message);
                    }
                }); //done---1st call     

                //Get currency
                $.get({
                    url: "/api/v1/country/" + country + "/currency",
                    contentType: "application/json; charset=utf-8"
                }).done(function (data, status, xhr) {
                    if ("SUCCESS" === data.code) {
                        logger.i("Info loaded successful");
                        //$("#vac").removeAttr("disabled");
                        var ret = data.returnobject;
                        $("#currencyspan").text(ret);
                    } else {
                        alertify.error(data.message);
                    }
                }); //done  

                $.get({
                    url: "/api/v1/country/" + country + "/exchangerate",
                    contentType: "application/json; charset=utf-8"
                }).done(function (data, status, xhr) {
                    if ("SUCCESS" === data.code) {
                        logger.i("Info loaded successful");
                        var ret = data.returnobject;
                        $("#exchangerate").val(ret);
                    } else {
                        alertify.error(data.message);
                    }
                }); //done---1st call     

                $.get({
                    url: "/api/v1/country/" + country + "/numofdecimals",
                    contentType: "application/json; charset=utf-8"
                }).done(function (data, status, xhr) {
                    if ("SUCCESS" === data.code) {
                        logger.i("Info loaded successful");
                        var numOfDecimals = data.returnobject;
                        $("#numofdecimals").val(numOfDecimals);
                    } else {
                        alertify.error(data.message);
                    }
                }); //done                          

                //------------------
                ubi.loader.blocking.stop();
            }
        });

        //-----2 Event-----------
        $("#vac").change(function () {
            let vac = $("#vac").val();
            if (vac !== 0 && vac !== undefined && vac !== '') {
                // Country
                ubi.loader.blocking.start();
                //-------1st call
                $.get({
                    url: "/api/v1/vac/" + vac + "/exchangerate",
                    contentType: "application/json; charset=utf-8"
                }).done(function (data, status, xhr) {
                    if ("SUCCESS" === data.code) {
                        logger.i("Info loaded successful");
                        var ret = data.returnobject;
                        $("#exchangerate").val(ret);
                    } else {
                        alertify.error(data.message);
                    }
                }); //done---1st call                                

                //------------------
                ubi.loader.blocking.stop();
            }
        });

        //-----3 Event-----------
        $('#isgratis').on('change', function (event) {
            var target = event.target;
            var isgratis = target.value;
            if (isgratis === 'true') {
                $("#costinref").val(0);
                $("#costinlocal").val(0);
                //hide
                $('#divroot').addClass("hidden");
                $('#divvac').addClass("hidden");
                $('#divdeclarebase').addClass("hidden");
                $('#divcostinlocal').addClass("hidden");
                $('#divcostinref').addClass("hidden");
                
            } else {
                $('#divroot').removeClass("hidden");
                $('#divvac').removeClass("hidden");
                $('#divdeclarebase').removeClass("hidden");
                $('#divcostinlocal').removeClass("hidden");
                $('#divcostinref').removeClass("hidden");                
            }
        });

        //-----4 Event-----------
        $('#costinlocal').on('change', function (event) {
            var target = event.target;
            var cost = target.value;
            var rate = document.getElementById('exchangerate').value;
            var declarebase = $("#declarebase :selected").val();  // declarebase==true (local)     declarebase==false (ref)                  
            console.log(cost, rate, declarebase);
            if (declarebase === 'true') {
                if (rate !== '' && rate !== '0') {      //TODO den fortonetai to rate
                    $("#costinref").val((cost / rate).toFixed(2));
                    $.each($("input#offeringvaccost"), function () {
                        $(this).val(cost);
                    });
                }
            }

        });

        //-----5 Event-----------
        $('#costinref').on('change', function (event) {
            var target = event.target;
            var cost = target.value;
            var rate = document.getElementById('exchangerate').value;
            var declarebase = $("#declarebase :selected").val();    // declarebase==true (local)     declarebase==false (ref)
//            alert(declarebase);                     
            console.log(cost, rate, declarebase);
            if (declarebase === 'false')
                if (rate !== '' && rate !== '0') {
                    var numOfDecimals = 2;
                    if ($('#numofdecimals').length){
                        numOfDecimals = $('#numofdecimals').val();
                    }
                    $("#costinlocal").val((cost * rate).toFixed(numOfDecimals));
                    $.each($("input#offeringvaccost"), function () {
                        $(this).val(cost);
                    });                    
                }
        });

        //----- Event-----------
        $('#root').on('change', function (event) {
            var target = event.target;
            var root = target.value;
            console.log(root);
            if (root === 'true'){                
                $("#vac option[selected]").removeAttr("selected");  
                $("#vac")[0].selectedIndex = 0;
                $("#vac").trigger('change'); 
                $("#vac").prop( "disabled", true );
                
                //$('#divvac').addClass("hidden");
        }else{
             //   $('#divvac').removeClass("hidden");
                $("#vac").prop( "disabled", false );
            }
        });

        //-----Event-----------
        $('#declarebase').on('change', function (event) {
            var target = event.target;
            var declarebase = target.value;
            console.log(declarebase);
            if (declarebase === 'true') {     //local
                $("#costinlocal").prop("disabled", false);
                $("#costinref").prop("disabled", true);
            } else {    //ref
                $("#costinref").prop("disabled", false);
                $("#costinlocal").prop("disabled", true);
            }
        });

    }//EoM
    
    function loadSearch() {
                
        $("#country").change(function () {
            varcommon.loadVacByCountry();
        });        
        
    }//EoM loadSearch

    router.addRoutePost('serviceoffering', loadSearch);
    router.addRoutePost('serviceoffering/:id', onEventsForServiceOffering);

})();

