     function select2Vas(){        
        $("#vas").select2({
            matcher: matchStart,
        });
        
        $("#country").change(function () {
            varcommon.loadVacByCountry();
        });        
        
    }//EoM loadSearch
 
    
    function matchStart(params, data){        
        
        if (typeof params.term === 'undefined'){
	    return data;
	}
        
        
	if (data.text.toUpperCase().indexOf(params.term.toUpperCase()) > -1 ||
            ($(data.element).attr("label")!=='' && typeof $(data.element).attr("label") !== 'undefined' && $(data.element).attr("label").toUpperCase().indexOf(params.term.toUpperCase()) > -1)||
            ($(data.element).attr("title")!=='' && typeof $(data.element).attr("title") !== 'undefined' && $(data.element).attr("title").toUpperCase().indexOf(params.term.toUpperCase()) > -1)
	 ){    
	    var modifiedData = $.extend({}, data, true);
	    return modifiedData;
	 }
         
	var modifiedData = $.extend(modifiedData, data, true);
	var currChildrenArray = [];
	$.each(data.children, function(index, elem){
	        if(elem.text.toUpperCase().indexOf(params.term.toUpperCase()) > -1){
		       currChildrenArray.push(elem);
	         }
	  });
	if(currChildrenArray.length > 0){
		modifiedData.children = currChildrenArray;
		return modifiedData;
	}
	return null;
    }

