(function () {
    'use strict';

    function onEventsForExchangerateplan() {
        //------------1
        $('#rate').on('input', function () {
            let rate = $('#rate').val();
            $.each( $("input#exchangerateplanvacrate.unlocked") , function(){
              $(this).val(rate);
            });
        });

        $('#activefrom').on('change', function () {
            let activefrom = $('#activefrom').val();
            $.each( $("input#exchangerateplanvacdate") , function(){
              $(this).val(activefrom); 
            });
        });
        
        $('#exchangerateplanvaclocked').change( function () {
            let locked = $('#exchangerateplanvaclocked').val();
            alert(locked);
        });
        //------------------2
        $("#country").change(function () {
            let country = $("#country").val();
            if (country !== 0 && country !== undefined && country !== '') {
                // Country
                ubi.loader.blocking.start();
                //-------------
                //Get currency
                $.get({
                    url: "/api/v1/country/" + country + "/currencies",
                    contentType: "application/json; charset=utf-8"
                }).done(function (data, status, xhr) {
                    if ("SUCCESS" === data.code) {
                        logger.i("Info loaded successful");
                        $("#vac").removeAttr("disabled");
                        var ret = data.returnobject;
                        
                        $("#currencyspan").text(ret[0]);
                        $("#excelcurrencyspan").text(ret[1]);
                        if (ret[0]!==ret[1]){
                            $("#excelratespan").removeClass("hidden");
                            $("#excelrateth").removeClass("hidden");   
                            $( "td[id^='excelratetd']" ).removeClass("hidden");                         
                        }else{
                            $("#excelratespan").addClass("hidden");
                            $("#excelrateth").addClass("hidden");   
                            $( "td[id^='excelratetd']" ).addClass("hidden");  
                        }
                        let ratePattern = ret[2];
                        let rateMessage = ret[3];
                                                
                        $('#rate').attr('pattern', ratePattern);
                        $('#rate').attr('data-parsley-pattern-message', rateMessage);
                        
                        $('#excelrate').attr('pattern', ratePattern);
                        $('#excelrate').attr('data-parsley-pattern-message', rateMessage);
                    } else {
                        alertify.error(data.message);
                    }
                }); //done       

                //------------------
                ubi.loader.blocking.stop();
            }
        });        
        
    }//EoM 
    
    function forceApply(data, textStatus, jqXHR){
        if (textStatus.toUpperCase() == "SUCCESS") {                  
            if (data.code === "EXCEPTION"){
              $('#btn-apply-exchangerateplan').addClass("hidden")
              $('#btn-force-exchangerateplan').removeClass("hidden")
            }
            
        }
    }
        
    router.addRoutePost('exchangerateplan');
    router.addRoutePost('exchangerateplan/:id', onEventsForExchangerateplan);
    router.addRoutePost('exchangerateplan/apply/:id');
    
    window.forceApply = forceApply;

})();

