(function () {

  'use strict';

  function onChangeCountry() {

    $("#country").change(function () {
      let country = $("#country").val();
      if (country !== 0 && country !== undefined && country !== '') {
        // Country
        ubi.loader.blocking.start();

        // send request to populate cities list
        $.get({
          url: "/api/v1/country/" + country + "/city",
          contentType: "application/json; charset=utf-8"
        }).done(function (data, status, xhr) {
          if ("SUCCESS" === data.code) {
            logger.i("Cities loaded successful");
            $("#city").removeAttr("disabled");
            var array = data.returnobject;
            var htmlVar = "";
            for (var i = 0; i < array.length; i++) {
              htmlVar += '<option value="' + array[i].id + '">'
                  + array[i].name
                  + '</option>';
            }
            $("#city").html(htmlVar);

          } else {
            alertify.error(data.message);
          }
          ubi.loader.blocking.stop();
        });

        // send request to populate travel agents list
        $.get({
          url: "/api/v1/country/" + country + "/travelagent",
          contentType: "application/json; charset=utf-8"
        }).done(function (data, status, xhr) {
          if ("SUCCESS" === data.code) {
            logger.i("TAs loaded successful");
            $("#travelagents").removeAttr("disabled");
            var array = data.returnobject;
            var htmlVar = "";
            for (var i = 0; i < array.length; i++) {
              htmlVar += '<option value="' + array[i].id + '">'
                  + array[i].name
                  + '</option>';
            }
            $("#travelagents").html(htmlVar);

          } else {
            alertify.error(data.message);
          }
          ubi.loader.blocking.stop();
        });
      }
    });
    
  }

  router.addRoutePost('consulate');
  router.addRoutePost('consulate/:id', onChangeCountry);

})();


