(function () {

    'use strict';
    

    function onGroupSelect() {
        //----- Event-----------
        $('#grouptype').on('change', function (event) {
            var seln = $('#grouptype :selected').text();
            //hide or show respectively
            if (seln === 'TRAVEL AGENCY' || seln === 'TRAVEL AGENCY FAMILY' || seln === 'TRAVEL AGENCY TRAVELLERS') {
                $('#divgroupname').addClass('hidden');
                $('#name').attr('required', false);
                $('#divtravelagent').removeClass('hidden');
                $('#travelagent').val(null).change();
                $('#travelagent').attr('required', true);
            } else {
                $('#divtravelagent').addClass('hidden');
                $('#travelagent').attr('required', false);
                $('#divgroupname').removeClass('hidden');
                $('#name').val(seln).change();
                $('#name').attr('required', true);
            }
        });
    }

    var multiCheck = function (chkbx) {
        var status = chkbx.checked;
        $('.varcheckbox').each(function() {
            this.checked=status;
        });
        singleCheck();
    };

    var singleCheck = function(chkbx) {
        //uncheck 'select all', if one of the listed checkbox item is unchecked
        if(false == $(chkbx).prop('checked')){ //if this item is unchecked
            $('#select_all').prop('checked', false); //change 'select all' checked status to false
        }
        //check 'select all' if all checkbox items are checked
        if ($('.varcheckbox:checked').length == $('.varcheckbox').length ){
            $('#select_all').prop('checked', true);
        }

        // disable/enable the button
        if ($('.varcheckbox:checked').length) {
            // $('#btn-multiremove-up').attr('disabled', false);
            // $('#btn-multiremove-down').attr('disabled', false);
            // $('#btn-multiadd-up').attr('disabled', false);
            // $('#btn-multiadd-down').attr('disabled', false);
            $('.multicheck').attr('disabled', false);
        } else {
            // $('#btn-multiremove-up').attr('disabled', true);
            // $('#btn-multiremove-down').attr('disabled', true);
            // $('#btn-multiadd-up').attr('disabled', true);
            // $('#btn-multiadd-down').attr('disabled', true);
            $('.multicheck').attr('disabled', true);
        }
    };

    function loadSearch() {
        $("#travelagent").change(function () {
            varcommon.loadTravelAgent();
        });
        $( document ).ready(function() {
            //$("#application").focus();
            //$( "#application" ).focus().focus();
            setTimeout(function() { $( "#name" ).focus() }, 300);
        });
    }//EoM loadSearch




    function onPrepareExport() {
        console.log("test labels");
        //create drop up buttons
        focusSearch();
        $("#btn-labels").click(function () {
            console.log("click");
            var dropupMenuID = "#"+this.id+"-myDropup";
            var dropupMenu = $(dropupMenuID);
            $(".dropup-content").not(dropupMenuID).hide();
            dropupMenu.toggle( "slow", function() {
                // Animation complete.
            });

            // on click of the document, close the menus
            $(document).one("click", function () {
                //menu.hide();
                dropupMenu.hide();
            });
            return false;
        });
    }//EoM

    function focusSearch() {
        $( document ).ready(function() {
            //$("#application").focus();
            //$( "#application" ).focus().focus();
            setTimeout(function() { $( "#application" ).focus() }, 300);
        });
    }

    router.addRoutePost('group/add', onGroupSelect);
    router.addRoutePost('group/:id', onPrepareExport);
    router.addRoutePost('group/:id/add', focusSearch);
    router.addRoutePost('group', loadSearch);

    window.multiCheck = multiCheck;
    window.singleCheck = singleCheck;

})();

