(function () {

    'use strict';
    
    function validateAll(data, textStatus, jqXHR){
        
        if (textStatus.toUpperCase() == "SUCCESS" && (data == "" || data === undefined || data.code.toUpperCase() === "SUCCESS")) {
            /*$('#btn-scan').hide();            
            if (data.returnobject!=null){
                $("[id^='statusview']" ).text('Validated');
            }*/
            
            $('#result').html('');
            $('#listdiv').hide();
            $('#btn-upload').hide();
            
            if (data && data.returnobject&&Array.isArray(data.returnobject)) {                                                 
                        
            var resultList = "";
            var dataCount = 0;

            data.returnobject.forEach(function (child) {
                var style = "background:#fff;color:#38aed9";
                if (child.errorFile===true){
                    style = "background:#fff;color:#FF5656;font-weight: bold;";
                }
                //console.log(child.fileName);
                //console.log(child.fileDownloadUri);

                resultList += '<li style="margin-top:20px"><button onclick="window.open(\'/download/' + child.fileName + '/b/excels/' + child.fileDownloadUri + '\');" class="btn" style="'+style+'" form="uploadvarsform">'+child.fileName+'</button></li>';
                dataCount++;

            });

            $('#resultMessage').show();
            if (dataCount>1){
                $('#result').append('<ol style="margin-top:20px">'+resultList+'</ol>');
            }else{
                $('#result').append('<ul style="margin-top:20px">'+resultList+'</ul>');
            }

          /*  setTimeout(function () {
                alertify.success(data.message);
                $btn.removeClass('loading');
            }, ubi.loader.blocking.loadingTime);*/
        }else if (data && data.returnobject && ((typeof data.returnobject) === 'string')){
            $('#resultMessage').show();
            $('#result').append('<span style="margin-top:20px;margin-top:20px;font-weight: bold;">'+data.returnobject+'</span>');
        }
            
        }
    }
    
    function loadSearch() {
        $('#loaderMsg').remove();
        $("#travelagent").change(function () {
            varcommon.loadTravelAgent();
        });
        
    }//EoM loadSearch
    
    router.addRoutePost('varbatchvalidator', loadSearch);

    window.validateAll = validateAll;
})();

