(function () {

    'use strict';
    function loadForm() {
        $("#datefrom").change(function () {
            var fromDate = $("#datefrom").val();
            var toDate = $("#dateto").val();
            checkDates(fromDate, toDate);
        });
        $("#dateto").change(function () {
            var fromDate = $("#datefrom").val();
            var toDate = $("#dateto").val();
            checkDates(fromDate, toDate);
        });

               $("#vac").change(function () {
                    let vac = $("#vac").val();

                    if (vac !== 0 && vac !== undefined && vac !== '') {
                        // Vac
                        ubi.loader.blocking.start();

                        // send request to populate travel agents list
                        $.get({
                            url: "/api/v1/vac/" + vac + "/appointmentypes",
                            contentType: "application/json; charset=utf-8"
                        }).done(function (data, status, xhr) {
                            if ("SUCCESS" === data.code) {
                                console.log("Types loaded successful");
                                logger.i("Types loaded successful");
                                console.log(data);
                                console.log(status);
                                console.log(xhr);
                                var array = data.returnobject;
        //                        htmlAppointmenttypes += '<option value="" text=""></option>';
                                var htmlAppointmenttypes = '<option value="" ></option>';
                                for (var i = 0; i < array.length; i++) {
                                    htmlAppointmenttypes += '<option value="' + array[i] +'">'
                                    + ubi.getTranslationExt("frontend.message.period.type."+array[i])
                                    + '</option>';
                                }

                                $("#type").html(htmlAppointmenttypes);
                            } else {
                                alertify.error(data.message);
                            }
                            ubi.loader.blocking.stop();
                        });
                        $('#type').val('').trigger('change');
                    }

                    if (vac !== 0 && vac !== undefined && vac !== '') {
        //                getTimezone(vac);
                    }
                });


    }//EoM loadForm

    function checkDates(fromDate, toDate){
        if (fromDate !== '' && toDate !== '') {
            if (createDateFromInput(fromDate) > createDateFromInput(toDate)) {
                alertify.error('The \'Date To\' should be always foregoing');
                return;
            }
        }
    }

    //Calculations
    function createDateFromInput(input) {
        var s = input.split('/'); //split Date of birth dd/MM/yyyy  Days = s[0] | Months = s[1] | Years = s[2]
        //he ISO 8601 syntax (YYYY-MM-DD)
        var newDateofFieldFormat = s[2] + '-' + s[1] + '-' + s[0];
        var dateoffieldDate = new Date(newDateofFieldFormat);
        dateoffieldDate.setHours(0, 0, 0, 0);
        return dateoffieldDate;
    }//EoM

    router.addRoutePost('period');
    router.addRoutePost('period/:id', loadForm);
    router.addRoutePost('period/:id/availability');

})();

