(function () {
    'use strict';

    function onUserEvents() {
        let countryID = $("#country").val();
        let userid = $("#id").val();        
        if ((userid === 0 || userid === undefined ||  userid === '' )
                && countryID !== 0 && countryID !== undefined && countryID !== '' ) {
            setLanguage(countryID)
        }

        $("#roles").change(function () {
            var countryRequired = true;
            var vacRequired = true;
            var tagentRequired = false;
            var callcenterRequired = false;
            $.each($("#roles  option:selected"), function(index, elem){
                if (elem.className && elem.className === 'nocountry' ){
                    countryRequired = false;
                    vacRequired = false;
                }else if (elem.className && elem.className === 'onlycountry' ){
                    countryRequired = true;
                    vacRequired = false;
                }else if (elem.className && elem.className === 'tagent' ){
                    countryRequired = true;
                    vacRequired = true;
                    tagentRequired = true;
                }else if (elem.className && elem.className === 'callcenter' ){
                    countryRequired = true;   
                    callcenterRequired = true;
                    vacRequired = false;
                }
            }); 
            $("#country").attr("required", countryRequired);
            if (countryRequired){                
                $("#country-wrap").addClass("required");
            }else{
                $("#country-wrap").removeClass("required");
            }
            $("#vac").attr("required", vacRequired);
            if (vacRequired){                
                $("#vac-wrap").addClass("required");
            }else{
                $("#vac-wrap").removeClass("required");
            }
            $("#travelagent").attr("required", tagentRequired);
            if (tagentRequired){                
                $("#travelagent-wrap").addClass("required");
                $("#travelagent-wrap").removeClass("hidden");
            }else{
                $("#travelagent-wrap").removeClass("required");
                $("#travelagent-wrap").addClass("hidden");
            }
            $("#contractor").attr("required", callcenterRequired);
            if (callcenterRequired){                
                $("#contractor-wrap").addClass("required");
            }else{
                $("#contractor-wrap").removeClass("required");
                $("#contractor").html('<option value=""></option>');
            }
            
        });

        $("#vac").change(function () {
            let vac = $("#vac").val();
            let travelagent = $("#travelagent").val();
            
            if (vac !== 0 && vac !== undefined && vac !== '' &&
                    travelagent != undefined) {
                // Vac
                ubi.loader.blocking.start();

                // send request to populate travel agents list
                $.get({
                    url: "/api/v1/vac/" + vac + "/travelagent",
                    contentType: "application/json; charset=utf-8"
                }).done(function (data, status, xhr) {
                    if ("SUCCESS" === data.code) {
                        logger.i("TAs loaded successful");
                        $("#travelagent").removeAttr("disabled");
                        var array = data.returnobject;
                        var htmlVar = "";
                        for (var i = 0; i < array.length; i++) {
                            htmlVar += '<option value="' + array[i].id + '">'
                                + array[i].name
                                + '</option>';
                        }
                        $("#travelagent").html(htmlVar);
                    } else {
                        alertify.error(data.message);
                    }
                    ubi.loader.blocking.stop();
                });
                $('#travelagent').val('').trigger('change');
            }
            
            if (vac !== 0 && vac !== undefined && vac !== '') {
                getTimezone(vac);
                
            }
        });

        $("#country").change(function () {
            let country = $("#country").val();
            if (country !== 0 && country !== undefined && country !== '') {
                // Country
                ubi.loader.blocking.start();
                let apiUrl = "/api/v1/country/" + country + "/vac";                           
                $.each($("#roles  option:selected"), function(index, elem){
                    if (elem.className && elem.className === 'cons' ){
                        apiUrl = "/api/v1/country/" + country + "/consulatevac";                        
                    }
                });                
                
                $.get({
                    url: apiUrl,
                    contentType: "application/json; charset=utf-8"
                }).done(function (data, status, xhr) {
                    if ("SUCCESS" === data.code) {
                        logger.i("Info loaded successful");
                        $("#vac").removeAttr("disabled");
                        var array = data.returnobject;
                        var htmlVar = "";
                        htmlVar += '<option value=""></option>'
                        for (var i = 0; i < array.length; i++) {
                            htmlVar += '<option value="' + array[i].id + '">'
                                    + array[i].name
                                    + '</option>';
                        }
                        $("#vac").html(htmlVar);
                    } else {
                        alertify.error(data.message);
                    }
                    ubi.loader.blocking.stop();
                }); //done
                //$("#travelagent:selected").prop("selected", false)

                //$('#vac').val('').trigger("change");

                let travelagent = $("#travelagent").val();
                if (travelagent != undefined){
                    ubi.loader.blocking.start();
                    apiUrl = "/api/v1/country/" + country + "/travelagent";

                    $.get({
                        url: apiUrl,
                        contentType: "application/json; charset=utf-8"
                    }).done(function (data, status, xhr) {
                        if ("SUCCESS" === data.code) {
                            logger.i("Info loaded successful");
                            $("#vac").removeAttr("disabled");
                            var array = data.returnobject;
                            var htmlVar = "";
                            htmlVar += '<option value=""></option>'
                            for (var i = 0; i < array.length; i++) {
                                htmlVar += '<option value="' + array[i].id + '">'
                                    + array[i].name
                                    + '</option>';
                            }
                            $("#travelagent").html(htmlVar);
                        } else {
                            alertify.error(data.message);
                        }
                        ubi.loader.blocking.stop();
                    }); //done*/
                }

                setLanguage(country);
                
                 $.each($("#roles  option:selected"), function(index, elem){
                    if (elem.className && elem.className === 'callcenter' ){
                       setCallcenter();
                    }
                });
            }
        });
        
    }//EoM onChangeCountry
    
    
    function setCallcenter(){
        let country = $("#country").val();
        if (country !== 0 && country !== undefined && country !== '') {
            // Country
            ubi.loader.blocking.start();
            let apiUrl = "/api/v1/contractor/" + country;                           
            
            $.get({
                url: apiUrl,
                contentType: "application/json; charset=utf-8"
            }).done(function (data, status, xhr) {
                if ("SUCCESS" === data.code) {
                    logger.i("Info loaded successful");
                    $("#contractor").removeAttr("disabled");
                    var array = data.returnobject;
                    var htmlVar = "";
                    htmlVar += '<option value=""></option>'
                    for (var i = 0; i < array.length; i++) {
                        htmlVar += '<option value="' + array[i].id + '">'
                                + array[i].name
                                + '</option>';
                    }
                    $("#contractor").html(htmlVar);
                } else {
                    alertify.error(data.message);
                }
            }); //done

        }
    }
    
    function setLanguage(country){    
        let selectedLanguage = $("#language").val();
        $.get({
            url: "/api/v1/country/" + country + "/languages",
            contentType: "application/json; charset=utf-8"
        }).done(function (data, status, xhr) {            
            if ("SUCCESS" === data.code) {
                logger.i("Info loaded successful");
                $("#language").removeAttr("disabled");
                var array = data.returnobject;
                var htmlVar = "";

                htmlVar += '<option value=""></option>'
                for (var i = 0; i < array.length; i++) {
                    htmlVar += '<option value="' + array[i].id + '">'
                            + array[i].value
                            + '</option>';
                }
                $("#language").html(htmlVar);
                if (selectedLanguage != undefined){
                    $("#language").val(selectedLanguage);
                    $("#language").trigger();
                }

            } else {
                alertify.error(data.message);
            }
        }); //done
    }
    
    function getTimezone(vac){
        // get the related timezone
        $.get({
            url: "/api/v1/vac/" + vac + "/timezone",
            contentType: "application/json; charset=utf-8"
        }).done(function (data, status, xhr) {
            if ("SUCCESS" === data.code) {                
                logger.i("TAs loaded successful");
                $("#timezone").val(data.returnobject).trigger('change');;
                
            } else {
                alertify.error(data.message);
            }
            ubi.loader.blocking.stop();
        });
    }
                
    function loadSearch() {
                
        $("#country").change(function () {
            varcommon.loadVacByCountry();
        });        
        
    }//EoM loadSearch

    function updateUserProfileHandler($this) {               
        ubi.crud["post"]($this, function (data) {
            if ("SUCCESS" === data.code) {
                $("#"+$this.id).attr("data-submit", "/user/logout");
                console.log("logout");
                console.log($("#"+$this.id).attr("data-submit"));
                ubi.logout($("#"+$this.id));
            }

        }, {skipValidation: false}); // if true skip validation
    }//EoM updateUserProfileHandler
    
    function changePassword() {
        setTimeout(function () {
            $("#btn-pass").attr("data-submit", "/api/v1/user/logout");
            $("#btn-pass").attr("data-redirect", "stay");
            
            var ajaxOptions = {
                url: "/api/v1/user/logout",
                type: 'post'
              };

            ajaxOptions.contentType = "application/json; charset=utf-8";
            
            $.ajax(ajaxOptions).done(function (data, textStatus, jqXHR) {
                    ubi.removeAccess();
                    ubi.goHome();

            });
        }, 2000);
            
    }//EoM changePassword
    
    function saveprofile($this){
        if ($($this).attr("profile") !== undefined && $($this).attr("profile") === "true" ) {            
            ubi.crud.put($this, changeLang);           
        }else{
            ubi.crud.put($this);
        }
    }
    
    function changeLang(){
        let locale = "en_US";
        let language = $("#language").val();
        switch (language){
            case "en": 
                locale = "en_US";
                break;
            case "ru": 
                locale = "ru_RU";
                break;
            case "am": 
                locale = "am_AM";
                break;
            case "cn": 
                locale = "cn_CN";
                break;
            case "ar": 
                locale = "ar";
                break;
            case "ku": 
                locale = "ku";
                break;
            case "sr": 
                locale = "sr";
                break;
            case "sq": 
                locale = "sq";
                break;                        
            case "in":
                locale = "in";
                break;
            default:
                locale = "en_US";
        }
        var value = $(".lang-selector[data-lang='"+locale+"']");
        if (value !== undefined) {
            value.click();
        }
    }
    
    function exportUsers($this){
        
    }
    
    function downloadUsersFile(data, textStatus, jqXHR){        
        var robj = data.returnobject;
        var validFileName = robj.fileName;
        var bucketName = "/b/excels";
        if (robj.repository && robj.repository !== "" && robj.repository !== undefined){                                    
            if (robj.repository === "-"){
                bucketName = "/file";
            }else{
                bucketName = "/b/"+ robj.repository;
            }
        }
        window.open('/download/' + validFileName + bucketName+'/' + robj.fileDownloadUri);
        
    }
    
    router.addRoutePost('user/changepassword');
    router.addRoutePost('user', loadSearch);
    router.addRoutePost('user/:id', onUserEvents);

    window.updateUserProfileHandler  = updateUserProfileHandler;
    window.changePassword  = changePassword ;
    window.saveprofile = saveprofile;
    window.downloadUsersFile = downloadUsersFile;    

})();

