(function () {

  'use strict';    

  function confirmPurge($this) {
    var data = $($this);
    var formID = data.attr('form'); //TODO - Check form attribute in old browsers (check in IE11 - passed)
    var hasForm = (formID !== undefined && formID != "") ? true : false;
    var filter = "";
    var statusList = $('#filterstatuslist').val();
    var lastUpdated = $('#numoflastupdated').val();
    if (statusList.includes('3') && lastUpdated.length !== 0) {
        //console.log("status includes new " + statusList);
        alert(ubi.getTranslationExt('frontend.purging.new'));
        return;
    } else {
        console.log("status does not include new");
    }
    if (hasForm) {
        // Define form
        var $form = $('form#' + formID);
        if ($form.length < 1) {
          throw new TypeError("No form found with id='" + formID + "'");
        }

        var fields = $form.serializeJSON(serializeJSON_OPTIONS);
        var field;
        for (field in fields) {
          if (typeof fields[field] === 'string') {
            fields[field] = fields[field].trim();
            if (field === "country" || field === "vac" || field === "filterstatus"){
              fields[field] = $( "#"+field+" option:selected" ).text();
            }
          }else if (field === "filterstatuslist"){              
              var text = "";
              $("#"+field+" option:selected").each(function () {
                var $this = $(this);
                if ($this.length) {
                 var selText = $this.text();
                 if (text.length) {
                  text += ", ";
                 }
                 text += selText;
                }
              });
              fields[field] = "["+text+"]";
          }
        }
        filter = (JSON.stringify(fields));
      }

      alertify.confirm(ubi.getTranslationExt('frontend.message.purging.title'), ubi.getTranslationExt('frontend.message.purging.message') + "\n"+filter,
            function(){ 
              ubi.crud.post($this);
            },
            function(){                
                alertify.alert(ubi.getTranslationExt('frontend.message.purging.title'), ubi.getTranslationExt('frontend.message.purging.cancelled'));
            }
        ).set({
            labels: {ok: ubi.getTranslationExt('frontend.message.purging.submit'), cancel: ubi.getTranslationExt('frontend.message.purging.cancel')},           
            reverseButtons: true,
            transition: 'fade'
        });
  }

  function confirmHalfPurge($this) {
      var statusList = $('#filterstatuslist').val();
      var lastUpdated = $('#numoflastupdated').val();
      if (statusList.includes('3') && lastUpdated.length !== 0) {
          //console.log("status includes new " + statusList);
          alert(ubi.getTranslationExt('frontend.purging.new'));
          //return;
      } else {
          console.log("status does not include new");
          ubi.crud.post($this);
      }
  }

  router.addRoutePost('purging'); 
  router.addRoutePost('purging/onebyone'); 
  router.addRoutePost('purging/unmask'); 
  router.addRoutePost('purging/unmask/onebyone'); 
  window.confirmPurge = confirmPurge;
  window.confirmHalfPurge = confirmHalfPurge;
  
})();


