(function () {

  'use strict';

  // Error pages
  function error(ctx) {
    if ("code" in ctx.params) {
      switch (ctx.params.code) {
        case "403":
          $('body').removeClass('gvcw').addClass('bg-tech error');
          $('#layout-container').html(
            '<div id="logo" onclick="location.replace(\'/\')"><img src="/dist/images/logo.png"/></div>' +
            '<h1>Access denied!!!</h1>'
          );
          localStorage.removeItem(ubi.TOKEN_KEY_NAME);
          break;
        case "404":
          $('body').removeClass('gvcw').addClass('bg-tech error');
          $('#layout-container').html(
            '<div id="logo" onclick="location.replace(\'/\')"><img src="/dist/images/logo.png"/></div>' +
            '<h1>Page not found!!!</h1>' +
            '<div id="back" onclick="ubi.goHome()">Homepage</div>'
        );
          break;
        default:
          $('body').removeClass('gvcw').addClass('bg-tech error');
          $('#layout-container').html(
            '<div id="logo" onclick="location.replace(\'/\')"><img src="/dist/images/logo.png"/></div>' +
            '<h1>Unknown error occurred. Please contact the system administrator.</h1>'
          );
      }
    }
  }

  // Page not found
  function notFound(ctx) {
    logger.e("Could not find pathname: " + ctx.pathname);
    //logger.d("Current state: " + JSON.stringify(ctx));

    $('body').removeClass('gvcw').addClass('bg-tech error');
    $('#layout-container').html(
      '<div id="logo" onclick="location.replace(\'/\')"><img src="/dist/images/logo.png"/></div>' +
      '<h1>Page not found!!!</h1>' +
      '<div id="back" onclick="ubi.goHome()">Homepage</div>'
    );
  }

  // setup error pages and then initialize
  router.addRouteCallback('error/:code', error);
  router.addRouteCallback('*', notFound);

  router.init();

})();

